def test_video_graph_builder_creates_store() -> None:
    builder = VideoGraphBuilder(ProjectPaths.from_env())
    store = builder.build("P08-20240617-130401")
    assert store.db_path.exists()
    with sqlite3.connect(store.db_path.as_posix()) as conn:
        node_count = conn.execute("SELECT COUNT(*) FROM nodes").fetchone()[0]
        edge_count = conn.execute("SELECT COUNT(*) FROM edges").fetchone()[0]
    assert node_count > 0
    assert edge_count > 0


def test_video_graph_builder_seeds_relation_edges() -> None:
    builder = VideoGraphBuilder(ProjectPaths.from_env())
    store = builder.build("P08-20240617-130401")
    edges = store.list_edges(video_id="P08-20240617-130401", limit=100000)
    edge_types = {str(edge.get("edge_type") or "") for edge in edges}
    assert "before" in edge_types
    assert "after" in edge_types
    assert "co_occurs" in edge_types
    assert "same_step" in edge_types


def test_retrievers_return_results() -> None:
    builder = VideoGraphBuilder(ProjectPaths.from_env())
    store = builder.build("P08-20240617-130401")
    time_retriever = TimeRetriever(store)
    object_retriever = ObjectRetriever(store)
    event_retriever = EventRetriever(store)
    assert time_retriever.retrieve(video_id="P08-20240617-130401", start_time=0.0, end_time=200.0, limit=5)
    assert object_retriever.retrieve(video_id="P08-20240617-130401", query="salad", limit=5)
    assert event_retriever.retrieve(video_id="P08-20240617-130401", event_types=["recipe_step"], limit=5)


def test_graph_agent_runs_multistep_loop_and_writes_observation(monkeypatch) -> None:
    paths = ProjectPaths.from_env()
    df = pd.read_parquet(paths.output_root / "event_index" / "vqa_samples.parquet")
    row = df[
        (df["primary_video_id"] == "P08-20240617-130401")
        & (df["task_family"] == "ingredient_ingredient_retrieval")
        & (df["correct_idx"] == 0)
    ].iloc[0].to_dict()

    def fake_extract_frames_for_range(self, *, video_path, start_time, end_time, stride_s=2.0, max_frames=8, prefix="range"):
        paths_out = []
        for index in range(2):
            out_path = self.workspace / f"{prefix}_{index:03d}.jpg"
            out_path.parent.mkdir(parents=True, exist_ok=True)
            Image.new("RGB", (64, 64), color=(255, 255, 255)).save(out_path)
            paths_out.append(out_path)
        return paths_out

    monkeypatch.setattr(VideoToolbox, "extract_frames_for_range", fake_extract_frames_for_range)

    class MockClient:
        def complete_json(self, messages, temperature=0.0):
            payload = json.loads(messages[1]["content"])
            snapshot = payload["working_memory"]
            times = payload["parsed_hints"]["times"]
            if snapshot["current_step"] == 0:
                return {"thought": "先查时间窗口。", "tool": "query_time", "args": {"start_time": times[0], "end_time": times[1], "limit": 8}}
            if snapshot["current_step"] == 1:
                return {
                    "thought": "需要回看视频片段。",
                    "tool": "extract_frames_for_range",
                    "args": {
                        "start_time": times[0],
                        "end_time": times[1],
                        "stride_s": 2.0,
                        "max_frames": 2,
                        "tag": "test_range",
                    },
                }
            if snapshot["current_step"] == 2:
                return {
                    "thought": "查看抽出的图像。",
                    "tool": "inspect_visual_evidence",
                    "args": {
                        "prompt": "请判断画面中最可能刚被加入的食材，输出 JSON。",
                        "image_paths": snapshot["retrieved_frames"][-2:],
                    },
                }
            if snapshot["current_step"] == 3:
                return {
                    "thought": "把视觉观察写回图谱。",
                    "tool": "write_observation",
                    "args": {
                        "label": "agent observed olive oil added",
                        "start_time": times[0],
                        "end_time": times[1],
                        "attributes": {"ongoing_action": "adding olive oil", "answer_hint": "olive oil"},
                        "evidence_paths": snapshot["retrieved_frames"][-2:],
                        "keywords": ["olive oil", "ingredient_add"],
                    },
                }
            return {
                "thought": "证据足够。",
                "tool": "finish",
                "args": {"prediction": 0, "answer": "0", "confidence": 0.92},
                "done": True,
            }

        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            return ModelResponse(content='{"ongoing_action":"adding olive oil","answer_hint":"olive oil"}', raw={})

        def complete(self, messages, temperature=0.0):
            return ModelResponse(content="0", raw={})

    agent = GraphAgent(paths=paths, model_client=MockClient())
    result = agent.answer_vqa_row(row, max_steps=5)
    assert result.prediction == 0
    assert any(trace["tool"] == "inspect_visual_evidence" for trace in result.tool_trace)
    assert any(trace["tool"] == "write_observation" for trace in result.tool_trace)
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")
    written = store.query_nodes(video_id="P08-20240617-130401", node_types=["observation"], keyword="olive oil", limit=10)
    assert written
    trace_path = paths.graph_agent_runs_root / "ingredient_ingredient_retrieval" / f"{row['vqa_id'].replace(':', '_')}.json"
    assert trace_path.exists()


def test_agent_toolbox_rank_choices_falls_back_without_json() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")

    class MockClient:
        def complete_json(self, messages, temperature=0.0):
            raise RuntimeError("empty response")

    toolbox = AgentToolbox(store=store, paths=paths, model_client=MockClient(), video_id="P08-20240617-130401")
    result = toolbox.rank_choices_from_state(
        question="Which ingredient was added?",
        choices=["olive oil", "salt", "tomato"],
        evidence=["ingredient_add olive oil", "adding olive oil into bowl"],
        working_memory=["answer_hint=olive oil"],
    )
    assert result["best_index"] == 0
    assert result["answer"] == "olive oil"


def test_agent_toolbox_rank_choices_uses_action_intent_prompt_for_why_question() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")

    class MockClient:
        def __init__(self) -> None:
            self.messages = None

        def complete_json(self, messages, temperature=0.0):
            self.messages = messages
            return {
                "scores": [
                    {"index": 0, "score": 0.22, "reason": "tap access is possible"},
                    {"index": 2, "score": 0.71, "reason": "same-object rinse evidence is stronger"},
                ],
                "best_index": 2,
                "answer": "to rinse the sponge while holding the white chop board in hand.",
                "confidence": 0.63,
            }

    client = MockClient()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=client, video_id="P08-20240617-130401")
    result = toolbox.rank_choices_from_state(
        question="What is the best description for why the person performed the action <move sponge> in video 1?",
        choices=[
            "so I can easily turn on the tap.",
            "so that I can lift the chop board and take the chop board to the sink.",
            "to rinse the sponge while holding the white chop board in hand.",
        ],
        evidence=["type=audio_event; label=water", "object_name=sponge", "object_name=white chopping board"],
        working_memory=["scene=sink"],
    )

    assert result["best_index"] == 2
    assert client.messages is not None
    assert "结构化因果裁决器" in client.messages[0]["content"]
    assert "直接目的" in client.messages[0]["content"]


def test_agent_toolbox_fallback_rank_choices_uses_structured_action_intent_signals_for_control_question() -> None:
    toolbox = AgentToolbox.__new__(AgentToolbox)

    result = toolbox._fallback_rank_choices(  # noqa: SLF001
        question="What is the best description for why the person performed the action <turn dial> in video 1?",
        choices=[
            "to pour out the water and rinse the bottom of the saucepan under the running water.",
            "to turn the dishwasher on.",
            "to stop the operation of the food processor having confirmed the food processor is correctly operating.",
        ],
        evidence=[
            "type=audio_event; label=kettle / mixer / appliance",
            "scene=appliance control area",
            "object=dial",
        ],
        working_memory=[],
    )

    assert result["best_index"] in {1, 2}
    assert "structured" in str(result["scores"][result["best_index"]]["reason"]).lower()


def test_agent_toolbox_query_ocr_expands_generic_reading_keyword() -> None:
    paths = ProjectPaths.from_env()
