def test_agent_toolbox_extract_ocr_keyword_avoids_bbox_false_positive() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")

    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise RuntimeError("unused")

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="P08-20240617-130401")
    assert (
        toolbox._extract_ocr_keyword(
            "How many times did I close the item indicated by bounding box <BBOX 1 2 3 4> in <TIME 00:00:58.5 video 1>?"
        )
        is None
    )
    assert (
        toolbox._extract_ocr_keyword(
            "Where did I take the object identified by <BBOX 1 2 3 4> at <TIME 00:04:16.867 video 1> from before putting it at <TIME 00:04:16.867 video 1>?"
        )
        is None
    )
    assert toolbox._extract_ocr_keyword("What is the reading on the scale for the onions? <TIME 00:00:10.000 video 1>") == "reading"


def test_agent_toolbox_inspect_visual_evidence_returns_vision_disabled_payload() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")

    class MockClient:
        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            raise RuntimeError("vision_not_supported:image_generation_disabled")

    toolbox = AgentToolbox(store=store, paths=paths, model_client=MockClient(), video_id="P08-20240617-130401")
    payload = toolbox.inspect_visual_evidence(prompt="look", image_paths=["/tmp/fake.jpg"])
    assert payload["tool_failed"] is True
    assert payload["vision_disabled"] is True
