def test_executor_initializes_vision_disabled_memory_when_provider_disables_vision() -> None:
    class DummyModelClient:
        def supports_vision_requests(self) -> bool:
            return False

        def vision_disable_reason(self) -> str:
            return "image_generation_disabled"

    class DummyToolbox:
        model_client = DummyModelClient()

    executor = GraphAgentExecutor.__new__(GraphAgentExecutor)
    executor.toolbox = DummyToolbox()
    executor.planner = None
    executor.verifier = GraphAgentVerifier()
    state = AgentState(video_id="vid", question="Where is the kettle?", choices=["a", "b"], task_family="open_query_location")
    executor._initialize_reasoning_state(state, {"times": [], "input_times": []})
    assert "vision_disabled=image_generation_disabled" in state.working_memory


