def test_agent_toolbox_infer_action_mechanism_uses_compact_visual_paths(tmp_path: Path) -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")

    class DummyClient:
        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            self.paths = image_paths
            return SimpleNamespace(content='{"best_index":1,"answer":"pull door","confidence":0.8,"reason":"visual"}', raw={})

        def _extract_json_object(self, text):
            import json
            return json.loads(text)

    client = DummyClient()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=client, video_id="vid")
    image_paths = []
    for index in range(3):
        path = tmp_path / f"frame_{index}.jpg"
        path.write_bytes(b"fake")
        image_paths.append(str(path))
    result = toolbox.infer_action_mechanism(
        question="How was the microwave opened?",
        choices=["press button", "pull door"],
        image_paths=image_paths,
    )
    assert result["best_index"] == 1
    assert len(client.paths) == 1


def test_planner_infer_action_mechanism_filters_non_visual_artifacts() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise RuntimeError("force heuristic fallback")

    planner = GraphAgentPlanner(DummyClient())
    state = type(
        "State",
        (),
        {
            "task_family": "fine_grained_how_recognition",
            "question": "How was the coffee beans bag opened?",
            "choices": ["pull apart", "cut with scissors"],
            "retrieved_frames": [
                "/tmp/frame_0.jpg",
                "annotations/hd-epic-annotations-main/audio-annotations/HD_EPIC_Sounds.csv",
                "/tmp/frame_1.png",
            ],
            "tool_trace": [],
            "working_memory": [],
            "evidence_bundle": [],
            "visited_times": [],
            "open_questions": [],
            "tool_failures": [],
            "ineffective_tools": [],
            "max_steps": 6,
            "snapshot": lambda self=None: {"current_step": 1},
        },
    )()
    decision = planner.next_action(
        state=state,
        tool_schemas=[],
        hints={"times": [1.0, 2.0], "input_times": [], "bbox": None},
    )
    assert decision.tool == "infer_action_mechanism"
    assert decision.args["image_paths"] == ["/tmp/frame_0.jpg", "/tmp/frame_1.png"]


def test_agent_toolbox_infer_action_mechanism_overrides_push_for_dishwasher_hinge_closure(tmp_path: Path) -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")

    class DummyClient:
        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            return SimpleNamespace(
                content=(
                    '{"best_index":2,"answer":"by pushing the door in.","confidence":0.93,'
                    '"reason":"The dishwasher door is already open downward, and the door is pushed inward/up to shut it."}'
                ),
                raw={},
            )

        def _extract_json_object(self, text):
            import json
            return json.loads(text)

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    frame = tmp_path / "frame.jpg"
    frame.write_bytes(b"fake")
    result = toolbox.infer_action_mechanism(
        question="What is the best description for how the person carried out the action <close dishwasher's door> in this video segment?",
        choices=[
            "using the left hand, leaving a gap",
            "using the left hand slowly.",
            "by pushing the door in.",
            "by twisting the handle using the left hand.",
            "by rotating the door upwards using the right hand.",
        ],
        image_paths=[str(frame)],
    )
    assert result["best_index"] == 4
    assert "hinged_drop_door_override" in result["reason"]


