def test_graph_agent_result_persists_markdown_evidence_report(tmp_path: Path) -> None:
    paths = ProjectPaths.from_env()
    agent = GraphAgent(paths=paths, model_client=SimpleNamespace())
    result = GraphAgentResult(
        vqa_id="open_query:vid:test",
        video_id="vid",
        task_family="open_query_temporal_summary",
        prediction=None,
        answer_text="the onion was mixed in the bowl",
        evidence_bundle=["type=timeline_event; label=mixing bowl"],
        tool_trace=[{"tool": "query_time", "result_summary": "nodes=2"}],
        raw_model_output="the onion was mixed in the bowl",
        working_memory=["possible_step=mixing bowl"],
        retrieved_frames=["/tmp/frame.jpg"],
        visited_times=[12.3, 15.8],
        artifacts=["/tmp/frame.jpg", "/tmp/crop.jpg"],
        confidence=0.8,
        elapsed_seconds=1.2,
    )
    row = {
        "question": "What happened?",
        "choices_json": '["OPEN_ENDED_RESPONSE"]',
        "inputs_json": "{}",
        "correct_idx": None,
    }
    agent._persist_evidence_report(result, row=row)
    report_path = paths.graph_agent_runs_root / "open_query_temporal_summary" / "open_query_vid_test.md"
    assert report_path.exists()
    text = report_path.read_text(encoding="utf-8")
    assert "## Visited Times" in text
    assert "12.300" in text
    assert "## Artifacts" in text
    assert "/tmp/crop.jpg" in text


