def test_graph_agent_video_session_restores_visited_times_and_artifacts(monkeypatch) -> None:
    paths = ProjectPaths.from_env()
    test_video_id = "P08-20240617-130401"

    class DummyClient:
        def complete(self, messages, temperature=0.0):
            return SimpleNamespace(content="summary")

    class DummyExecutor:
        def execute(self, state):
            state.add_visited_time(21.5)
            state.add_artifact("/tmp/reused_frame_021.500s.jpg")
            state.add_evidence("type=timeline_event; label=stirring bowl")
            state.final_answer = "summary"
            state.confidence = 0.7
            return state

    session = GraphAgent(paths=paths, model_client=DummyClient()).begin_video_session(test_video_id)
    monkeypatch.setattr(session, "executor", DummyExecutor())
    first = session.answer_open_query(question="What happened?", task_family="open_query_temporal_summary", max_steps=1)
    assert 21.5 in first.visited_times
    assert "/tmp/reused_frame_021.500s.jpg" in first.artifacts

    session2 = GraphAgent(paths=paths, model_client=DummyClient()).begin_video_session(test_video_id)
    assert 21.5 in session2.persisted_memory.get("visited_times", [])
    assert "/tmp/reused_frame_021.500s.jpg" in session2.persisted_memory.get("artifacts", [])


