def test_agent_toolbox_infer_object_drop_location_uses_final_fixture() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")

    class DummyClient:
        pass

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="P08-20240617-130401")
    toolbox.resolve_bbox_reference = lambda **kwargs: {
        "association_id": "assoc-1",
        "object_name": "whisk",
        "fixture": "P08_counter.004",
        "tracks": [
            {"track_index": 0, "start_time": 10.0, "end_time": 12.0, "masks": ["m1"]},
            {"track_index": 1, "start_time": 14.0, "end_time": 18.0, "masks": ["m2"]},
        ],
    }
    toolbox._resolve_fixture_from_mask_ids = lambda mask_ids: "P08_counter.005" if "m2" in mask_ids else "P08_counter.004"
    toolbox._resolve_fixture_sequence_from_mask_ids = lambda **kwargs: ["P08_counter.005"] if "m2" in (kwargs.get("mask_ids") or []) else ["P08_counter.004"]
    result = toolbox.infer_object_drop_location(
        bbox=[0.1, 0.1, 0.3, 0.3],
        reference_time=15.0,
        choices=[
            "counter top right from dishwasher",
            "drawer right from fridge",
            "windowsill",
            "top of storage",
            "counter left from sink",
        ],
        question="Where did I put the object after taking it?",
    )
    assert result["best_index"] == 4
    assert result["answer"] == "counter left from sink"
    assert result["final_fixture"] == "P08_counter.005"


