def test_agent_toolbox_infer_visual_mcq_uses_structured_object_contents_shortcut() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P05-20240424-090812")

    class DummyClient:
        def inspect_images(self, **kwargs):
            raise AssertionError("structured object contents shortcut should avoid visual model call")

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="P05-20240424-090812")
    toolbox.set_runtime_context(
        question=(
            "Which of these objects did the person put in/on the item indicated by bounding box "
            "<BBOX 571.6637929195265 476.59192161967644 784.8575977221292 863.2485887475434> "
            "in <TIME 00:00:17.0 video 1>?"
        ),
        inputs_json='{"video 1": {"id": "P05-20240424-090812"}}',
    )
    toolbox.query_spatial_context = lambda **kwargs: {
        "object_tracks": [
            {
                "object_name": "bowl",
                "track_index": 0,
                "start_time": 16.891,
                "end_time": 18.55689,
                "masks": ["b1", "b2"],
                "fixture": "P05_microwave.001",
            },
            {
                "object_name": "tablespoon",
                "track_index": 0,
                "start_time": 7.227,
                "end_time": 24.49286,
                "masks": ["s1", "s2"],
                "fixture": "P05_counter.006",
            },
        ],
        "object_masks": [],
        "gaze_priming": [],
        "audio_events": [],
        "count": 2,
    }
    toolbox._fixture_path_from_tracks = lambda tracks, reference_fixture="": {
        "bowl": ["P05_counter.005", "P05_microwave.001"],
        "tablespoon": ["P05_counter.006"],
    }.get(str(tracks[0].get("object_name") or ""), [])
    result = toolbox.infer_visual_mcq(
        question=toolbox.runtime_question,
        choices=[
            "bowl",
            "white plate, microwave oven",
            "cardboard box, scale",
            "Nothing",
            "wooden chopping board",
        ],
        image_paths=[],
    )
    assert result["best_index"] == 0
    assert result["answer"] == "bowl"
    assert "object_contents_structured" in result["reason"]


