    class DummyClient:
        pass

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    image_paths = []
    for index in range(8):
        image_path = tmp_path / f"frame_{index}.jpg"
        image_path.write_bytes(b"fake")
        image_paths.append(str(image_path))
    selected = toolbox._select_compact_visual_paths(image_paths=image_paths, max_images=4)  # noqa: SLF001
