def test_action_intent_followup_decision_routes_towel_transport_cluster_to_future_use_when_top_candidates_miss_relocation() -> None:
    needs, reason, window_s, resolver = action_intent_followup_decision(
        question="What is the best description for why the person performed the action <pick up tea towel> in video 1?",
        choices=[
            "to put the tea towel away.",
            "to dry kitchen scale.",
            "to dry both hands.",
            "to dry the hands.",
            "to clean and dry hand.",
        ],
        indices=[1, 3],
        confidence=0.63,
        reason_text="both drying the scale and drying the hands still look plausible",
    )

    assert needs is True
    assert reason == "transport_vs_cleanup_future_use_needed"
    assert window_s == 8.0
    assert resolver == "future_use"


