def test_agent_toolbox_pairwise_uses_action_intent_visual_path_selection_and_frame_sequence(tmp_path: Path) -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    captured: dict[str, object] = {}

    class DummyClient:
        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            captured["prompt"] = prompt
