def test_agent_toolbox_finish_allows_none_prediction() -> None:
    toolbox = AgentToolbox.__new__(AgentToolbox)

    result = toolbox.finish(prediction=None, answer="", confidence=0.0)

    assert result["done"] is True
    assert result["prediction"] is None
