def test_agent_toolbox_writeback_tools_persist_structured_nodes_and_edges(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph(
        [
            GraphNodeRecord(
                node_id="video:vid",
                node_type="video",
                label="vid",
                video_id="vid",
                start_time=0.0,
                end_time=100.0,
                attributes={"path": "/tmp/fake.mp4"},
                evidence_paths=["/tmp/fake.mp4"],
                keywords=["vid"],
            ),
            GraphNodeRecord(
                node_id="frame:vid:0001",
                node_type="frame",
                label="mixing in bowl",
                video_id="vid",
                start_time=12.3,
                end_time=12.3,
                attributes={"frame_id": "0001", "observation": {"scene_location": "counter"}},
                evidence_paths=["/tmp/frame.jpg"],
                keywords=["mixing", "bowl"],
            ),
            GraphNodeRecord(
                node_id="timeline:vid:0002",
                node_type="timeline_event",
                label="stirring bowl",
                video_id="vid",
                start_time=12.0,
                end_time=12.6,
                attributes={"summary": "stirring bowl"},
                evidence_paths=["/tmp/frame.jpg"],
                keywords=["stirring", "bowl"],
            ),
        ],
        [
            GraphEdgeRecord(
                edge_id="contains:vid:frame1",
                source_id="video:vid",
                target_id="frame:vid:0001",
                edge_type="contains",
                video_id="vid",
                attributes={},
            )
        ],
    )

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    frame_obs = toolbox.write_frame_observation(
        frame_path="/tmp/frame.jpg",
        time_s=12.3,
        label="agent sees chopped onion",
        observation={"visible_ingredient": "onion"},
        keywords=["onion", "chopped"],
        source_tool="inspect_visual_evidence",
        confidence=0.81,
    )
    ocr_obs = toolbox.write_ocr_reading(
        label="scale reading",
        reading="98 g",
        time_s=12.3,
        image_path="/tmp/scale.jpg",
        bbox=[1, 2, 3, 4],
        attributes={"unit": "g"},
        keywords=["98 g", "scale"],
        source_tool="run_ocr_on_region",
        confidence=0.93,
    )
    state_change = toolbox.write_state_change(
        label="onion softened",
        target="onion",
        before_state="raw",
        after_state="softened",
        start_time=12.3,
        end_time=20.0,
        evidence_paths=["/tmp/frame.jpg"],
        keywords=["onion", "softened"],
        source_tool="inspect_visual_evidence",
        confidence=0.77,
    )

    frame_node = store.get_node(frame_obs["node_id"])
    ocr_node = store.get_node(ocr_obs["node_id"])
    state_node = store.get_node(state_change["node_id"])
    assert frame_node is not None
    assert frame_node["attributes"]["observation"]["visible_ingredient"] == "onion"
    assert frame_node["attributes"]["source_tool"] == "inspect_visual_evidence"
    assert frame_node["attributes"]["confidence"] == 0.81
    assert ocr_node is not None
    assert ocr_node["attributes"]["reading"] == "98 g"
    assert ocr_node["attributes"]["source_tool"] == "run_ocr_on_region"
    assert ocr_node["attributes"]["confidence"] == 0.93
    assert state_node is not None
    assert state_node["attributes"]["after_state"] == "softened"
    assert state_node["attributes"]["source_tool"] == "inspect_visual_evidence"
    assert state_node["attributes"]["confidence"] == 0.77

    derived_edges = store.get_neighbors(node_ids=[frame_obs["node_id"], ocr_obs["node_id"]], edge_types=["derived_from"], limit=10)
    assert len(derived_edges) >= 2
    co_occurs_edges = store.get_neighbors(node_ids=[frame_obs["node_id"], ocr_obs["node_id"], state_change["node_id"]], edge_types=["co_occurs"], limit=20)
    assert co_occurs_edges
    same_relation_edges = store.get_neighbors(node_ids=[frame_obs["node_id"], state_change["node_id"]], edge_types=["same_object", "same_step"], limit=20)
    assert same_relation_edges
    temporal_edges = store.get_neighbors(node_ids=[state_change["node_id"]], edge_types=["before", "after"], limit=20)
    assert temporal_edges


def test_agent_toolbox_sparse_frames_and_ocr_and_audio_tools(monkeypatch) -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P08-20240617-130401")
    if not store.query_nodes(video_id="P08-20240617-130401", limit=1):
        store = VideoGraphBuilder(paths).build("P08-20240617-130401")

    class MockClient:
        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            return ModelResponse(content='{"text":"98 g","reading":"98 g","confidence":0.9}', raw={})

        def _extract_json_object(self, text):
            return json.loads(text)

    toolbox = AgentToolbox(store=store, paths=paths, model_client=MockClient(), video_id="P08-20240617-130401")

    def fake_sample_sparse_frames(self, *, video_path, start_time, end_time, sample_count, prefix):
        out = []
        for i in range(sample_count):
            path = self.workspace / f"{prefix}_{i:03d}.jpg"
            path.parent.mkdir(parents=True, exist_ok=True)
            Image.new("RGB", (64, 64), color=(255, 255, 255)).save(path)
            out.append(path)
        return out

    def fake_extract_region_with_context(self, *, image_path, bbox, expand_ratio, output_name):
        path = self.workspace / output_name
        path.parent.mkdir(parents=True, exist_ok=True)
        Image.new("RGB", (64, 64), color=(255, 255, 255)).save(path)
        return path

    def fake_detect_audio_peaks(self, *, video_path, start_time, end_time, window_s, top_k):
        return [{"time_s": 12.5, "window_start": 12.0, "window_end": 12.5, "score": 0.7}]

    monkeypatch.setattr(VideoToolbox, "sample_sparse_frames", fake_sample_sparse_frames)
    monkeypatch.setattr(VideoToolbox, "extract_region_with_context", fake_extract_region_with_context)
    monkeypatch.setattr(VideoToolbox, "detect_audio_peaks", fake_detect_audio_peaks)

    sparse = toolbox.sample_sparse_frames(start_time=10.0, end_time=14.0, sample_count=4, tag="sparse")
    assert sparse["count"] == 4
    assert len(sparse["artifact_paths"]) == 4

    ocr = toolbox.run_ocr_on_region(image_path=sparse["artifact_paths"][0], bbox=[1, 2, 20, 20], expand_ratio=0.3, tag="ocr")
    assert ocr["reading"] == "98 g"

    peaks = toolbox.detect_audio_peaks(start_time=10.0, end_time=14.0, window_s=0.5, top_k=3)
    assert peaks["count"] == 1
    assert peaks["peaks"][0]["time_s"] == 12.5


