def test_executor_auto_writes_visual_ocr_audio_observations(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph(
        [
            GraphNodeRecord(
                node_id="video:vid",
                node_type="video",
                label="vid",
                video_id="vid",
                start_time=0.0,
                end_time=100.0,
                attributes={"path": "/tmp/fake.mp4"},
                evidence_paths=["/tmp/fake.mp4"],
                keywords=["vid"],
            )
        ],
        [],
    )

    class DummyPlanner:
        pass

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    executor = GraphAgentExecutor(toolbox, DummyPlanner())
    state = AgentState(video_id="vid", question="q", choices=["a"], task_family="recipe_step_recognition")
    state.retrieved_frames = ["/tmp/frame_000_012.300s.jpg", "/tmp/frame_001_013.100s.jpg"]

    visual_payload = {
        "possible_step": "stirring bowl",
        "ongoing_action": "stirring",
        "target_object": "bowl",
        "state_change_hint": "mixing ingredients",
        "raw_output": "stirring bowl",
    }
    executor._merge_result_into_state(state, "inspect_visual_evidence", visual_payload)
    ocr_payload = {
        "reading": "98 g",
        "text": "98 g",
        "artifact_path": "/tmp/scale_012.300s.jpg",
        "confidence": 0.9,
    }
    state.record_tool("run_ocr_on_region", {"image_path": "/tmp/scale.jpg", "bbox": [1, 2, 3, 4]}, "ocr", raw_result=ocr_payload)
    executor._merge_result_into_state(state, "run_ocr_on_region", ocr_payload)
    peaks_payload = {
        "peaks": [{"time_s": 12.5, "window_start": 12.0, "window_end": 12.5, "score": 0.7}],
    }
    executor._merge_result_into_state(state, "detect_audio_peaks", peaks_payload)

    timeline_nodes = store.query_nodes(video_id="vid", node_types=["timeline_event"], keyword="stirring", limit=10)
    ocr_nodes = store.query_nodes(video_id="vid", node_types=["ocr_reading"], keyword="98 g", limit=10)
    audio_nodes = store.query_nodes(video_id="vid", node_types=["audio_event"], keyword="audio peak", limit=10)
    assert timeline_nodes
    assert any("stirring" in json.dumps(node["attributes"], ensure_ascii=False).lower() for node in timeline_nodes)
    assert timeline_nodes[0]["attributes"]["source_tool"] == "inspect_visual_evidence"
    assert ocr_nodes
    assert ocr_nodes[0]["attributes"]["reading"] == "98 g"
    assert ocr_nodes[0]["attributes"]["source_tool"] == "run_ocr_on_region"
    assert ocr_nodes[0]["attributes"]["confidence"] == 0.9
    assert audio_nodes
    assert audio_nodes[0]["attributes"]["source_tool"] == "detect_audio_peaks"


