def test_executor_tracks_open_questions_and_hypotheses(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph(
        [
            GraphNodeRecord(
                node_id="video:vid",
                node_type="video",
                label="vid",
                video_id="vid",
                start_time=0.0,
                end_time=100.0,
                attributes={"path": "/tmp/fake.mp4"},
                evidence_paths=["/tmp/fake.mp4"],
                keywords=["vid"],
            )
        ],
        [],
    )

    class DummyPlanner:
        def next_action(self, *, state, tool_schemas, hints):
            if state.current_step == 0:
                return PlannerDecision(
                    thought="先读取数字证据。",
                    tool="run_ocr_on_image",
                    args={"image_path": "/tmp/fake.jpg"},
                )
            return PlannerDecision(
                thought="证据足够，结束。",
                tool="finish",
                args={"prediction": 0, "answer": "0", "confidence": 0.9},
                done=True,
                answer="0",
                prediction=0,
                confidence=0.9,
            )

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    executor = GraphAgentExecutor(toolbox, DummyPlanner())
    state = AgentState(
        video_id="vid",
        question="What is the weight reading shown on the scale?",
        choices=["98 g"],
        task_family="ingredient_ingredient_weight",
    )

    def fake_run(tool_name, args):
        assert tool_name == "run_ocr_on_image"
        return {"reading": "98 g", "text": "98 g", "artifact_path": "/tmp/scale.jpg"}

    toolbox.run = fake_run
    toolbox.finish = lambda **kwargs: kwargs
    executor.execute(state)
    assert "need_ocr_reading" not in state.open_questions
    assert any(item == "ocr_evidence_collected" for item in state.hypotheses)
    assert any(item.startswith("planner_thought=") for item in state.working_memory)


def test_executor_recovers_from_tool_failure_and_continues(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph(
        [
            GraphNodeRecord(
                node_id="video:vid",
                node_type="video",
                label="vid",
                video_id="vid",
                start_time=0.0,
                end_time=100.0,
                attributes={"path": "/tmp/fake.mp4"},
                evidence_paths=["/tmp/fake.mp4"],
                keywords=["vid"],
            )
        ],
        [],
    )

    class DummyPlanner:
        def next_action(self, *, state, tool_schemas, hints):
            if not state.tool_failures:
                return PlannerDecision(
                    thought="先 OCR。",
                    tool="run_ocr_on_image",
                    args={"image_path": "/tmp/fail.jpg"},
                )
            return PlannerDecision(
                thought="OCR 失败后直接结束当前测试。",
                tool="finish",
                args={"prediction": 0, "answer": "0", "confidence": 0.6},
                done=True,
                answer="0",
                prediction=0,
                confidence=0.6,
            )

    class DummyClient:
        pass

    class AllowVerifier:
        def verify(self, *, state):
            return VerificationResult(
                sufficient=True,
                confidence=0.9,
                missing_evidence_types=[],
                conflicts=[],
                recommend_next_action="finish",
                summary="forced allow",
            )

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    executor = GraphAgentExecutor(toolbox, DummyPlanner(), AllowVerifier())
    state = AgentState(video_id="vid", question="What is the reading?", choices=["0"], task_family="ingredient_ingredient_weight")

    def fake_run(tool_name, args):
        raise RuntimeError("ocr backend down")

    toolbox.run = fake_run
    toolbox.finish = lambda **kwargs: kwargs
    executor.execute(state)
    assert state.final_prediction == 0
    assert state.tool_failures
    assert state.tool_failures[0]["tool"] == "run_ocr_on_image"
    assert any(item.startswith("tool_failure tool=run_ocr_on_image") for item in state.working_memory)


def test_executor_finishes_with_best_guess_when_budget_is_exhausted(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph([], [])

    class DummyPlanner:
        def next_action(self, *, state, tool_schemas, hints):
            return PlannerDecision(
                thought="预算耗尽前尝试直接结束。",
                tool="finish",
                args={"prediction": 1, "answer": "b", "confidence": 0.33},
                done=True,
                answer="b",
                prediction=1,
                confidence=0.33,
            )

    class BudgetVerifier:
        def verify(self, *, state):
            return VerificationResult(
                sufficient=False,
                confidence=0.33,
                missing_evidence_types=["need_disambiguating_evidence"],
                conflicts=[],
                recommend_next_action="need_disambiguating_evidence",
                summary="budget exhausted test",
                evidence_gaps=[{"gap_type": "relation_confirmation", "priority": "medium", "missing_observation": "x"}],
                sufficiency_decision={
                    "sufficient": False,
                    "missing_gap_types": ["relation_confirmation"],
                    "blocking_hypotheses": ["need_disambiguating_evidence"],
                    "recommended_next_step": "need_disambiguating_evidence",
                    "finish_mode": "finish_budget_exhausted_best_guess",
                    "summary": "budget exhausted test",
                },
            )

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    executor = GraphAgentExecutor(toolbox, DummyPlanner(), BudgetVerifier())
    state = AgentState(video_id="vid", question="q", choices=["a", "b"], task_family="fine_grained_why_recognition", max_steps=1)
    toolbox.finish = lambda **kwargs: kwargs
    executor.execute(state)
    assert state.final_prediction == 1
    assert state.final_answer == "b"
    assert state.verification_history
    assert state.verification_history[0]["sufficiency_decision"]["finish_mode"] == "finish_budget_exhausted_best_guess"
    assert state.final_metadata["finish_reason"] == "finish_budget_exhausted_best_guess"
    assert state.final_metadata["remaining_gaps"][0]["gap_type"] == "relation_confirmation"
    assert state.final_metadata["final_support_summary"] == "budget exhausted test"
    assert "used_budget" in state.final_metadata


