            return VerificationResult(
                sufficient=False,
                confidence=0.41,
                missing_evidence_types=[],
                conflicts=["conflicting_locations"],
                recommend_next_action="conflicting_locations",
                summary="location conflict remains",
                evidence_gaps=[],
                sufficiency_decision={},
            )

