def test_executor_uses_verifier_to_block_finish_until_evidence_exists(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph(
        [
            GraphNodeRecord(
                node_id="video:vid",
                node_type="video",
                label="vid",
                video_id="vid",
                start_time=0.0,
                end_time=100.0,
                attributes={"path": "/tmp/fake.mp4"},
                evidence_paths=["/tmp/fake.mp4"],
                keywords=["vid"],
            )
        ],
        [],
    )

    class DummyPlanner:
        def next_action(self, *, state, tool_schemas, hints):
            if state.current_step == 0:
                return PlannerDecision(
                    thought="先尝试直接结束。",
                    tool="finish",
                    args={"prediction": 0, "answer": "0", "confidence": 0.9},
                    done=True,
                    answer="0",
                    prediction=0,
                    confidence=0.9,
                )
            if state.current_step == 1:
                return PlannerDecision(
                    thought="补 OCR 证据。",
                    tool="run_ocr_on_image",
                    args={"image_path": "/tmp/scale.jpg"},
                )
            return PlannerDecision(
                thought="现在结束。",
                tool="finish",
                args={"prediction": 0, "answer": "0", "confidence": 0.9},
                done=True,
                answer="0",
                prediction=0,
                confidence=0.9,
            )

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    verifier = GraphAgentVerifier()
    executor = GraphAgentExecutor(toolbox, DummyPlanner(), verifier)
    state = AgentState(video_id="vid", question="What is the reading?", choices=["0"], task_family="ingredient_ingredient_weight")

    def fake_run(tool_name, args):
        assert tool_name == "run_ocr_on_image"
        return {"reading": "10 g", "text": "10 g", "artifact_path": "/tmp/scale.jpg"}

    toolbox.run = fake_run
    toolbox.finish = lambda **kwargs: kwargs
    executor.execute(state)
    assert state.final_prediction == 0
    assert any(item.startswith("verifier=") for item in state.working_memory)
    assert any(item.startswith("ocr_reading=") for item in state.working_memory)
    assert state.verification_history
    assert state.verification_history[0]["sufficient"] is False
    assert "need_ocr_reading" in state.verification_history[0]["missing_evidence_types"]


