def test_executor_object_motion_prunes_irrelevant_open_questions_after_structured_count(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph([], [])

    class DummyClient:
        pass

    class DummyPlanner:
        def __init__(self):
            self.calls = 0

        def next_action(self, *, state, tool_schemas, hints):
            self.calls += 1
            if self.calls == 1:
                return PlannerDecision(
                    thought="先估计运动次数。",
                    tool="estimate_object_movement_count",
                    args={"bbox": [0.1, 0.1, 0.3, 0.3], "reference_time": 81.733, "choices": state.choices},
                )
            return PlannerDecision(
                thought="结束当前测试。",
                tool="finish",
                args={"prediction": 4, "answer": "3", "confidence": 0.86},
                done=True,
                answer="3",
                prediction=4,
                confidence=0.86,
            )

    class AllowVerifier:
        def verify(self, *, state):
            return VerificationResult(
                sufficient=True,
                confidence=0.86,
                missing_evidence_types=[],
                conflicts=[],
                recommend_next_action="finish",
                summary="forced allow",
            )

        def detect_conflicts(self, *, state):
            return []

    toolbox = AgentToolbox(store=store, paths=ProjectPaths.from_env(), model_client=DummyClient(), video_id="vid")
    toolbox.estimate_object_movement_count = lambda **kwargs: {
        "movement_count": 3,
        "best_index": 4,
        "answer": "3",
        "object_name": "knife",
        "confidence": 0.86,
    }
    executor = GraphAgentExecutor(toolbox, DummyPlanner(), AllowVerifier())
    state = AgentState(
        video_id="vid",
        question="How many times did this object move?",
        choices=["6", "7", "5", "1", "3"],
        task_family="object_motion_object_movement_counting",
        inputs_json='{"image 1":{"time":"00:01:21.733","id":"vid"}}',
    )
    state.open_questions = [
        "need_region_grounding",
        "need_location_evidence",
        "need_state_evidence",
        "need_alternative_evidence_path",
        "need_time_localization",
    ]
    executor.execute(state)
    assert any(item.startswith("movement_count=3 best_index=4") for item in state.working_memory)
    assert "need_region_grounding" not in state.open_questions
    assert "need_location_evidence" not in state.open_questions
    assert "need_state_evidence" not in state.open_questions
    assert "need_alternative_evidence_path" not in state.open_questions


