def test_verifier_action_intent_plausible_competing_candidate_gap_is_not_driven_by_specialized_tool_name() -> None:
    verifier = GraphAgentVerifier()
    payload = {
        "best_index": 0,
        "second_best_index": 1,
        "confidence": 0.88,
        "reason": "the bottle is picked up and then placed back into the fridge immediately after pickup",
        "decisive_observation": "the bottle is clearly returned to the fridge and the door is closed right afterwards",
        "direct_effect": "the bottle is lifted away from the shelf",
        "downstream_action": "the bottle is placed back into the fridge immediately afterwards",
        "candidate_evidence": [
            {"index": 0, "score": 0.51, "support": "the bottle is returned to the fridge"},
            {"index": 1, "score": 0.49, "support": "the bottle front is briefly visible first"},
        ],
    }
    state_a = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to put the bottle back in the fridge.",
            "to check the label.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state_b = AgentState(
        video_id="vid",
        question=state_a.question,
        choices=list(state_a.choices),
        task_family="fine_grained_why_recognition",
    )
    state_a.tool_trace = [{"tool": "resolve_action_intent_pairwise", "raw_result": dict(payload)}]
    state_b.tool_trace = [{"tool": "resolve_action_intent_future_use", "raw_result": dict(payload)}]

    assert verifier._action_intent_has_plausible_competing_candidate_gap(state_a) is False  # noqa: SLF001
    assert verifier._action_intent_has_plausible_competing_candidate_gap(state_b) is False  # noqa: SLF001


