def test_verifier_action_intent_gap_targets_can_come_from_recent_observation_trace() -> None:
    verifier = GraphAgentVerifier()
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move bottle> in video 1?",
        choices=[
            "to make space.",
            "so that I can take the hidden spice jar behind it.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.open_questions = ["need_location_evidence"]
    state.evidence_bundle = ["type=timeline_event; label=bottle moved near shelf area"]
    state.tool_trace = [
        {
            "tool": "query_object",
            "args": {"query": "jar", "limit": 24},
            "raw_result": {
                "nodes": [
                    {"node_type": "object_track", "start_time": 407.1, "end_time": 408.0, "attributes": {"object_name": "jar"}},
                ]
            },
        },
        {
            "tool": "query_spatial_context",
            "args": {"time_s": 407.3, "object_name": "bottle", "fixture": "shelf", "limit": 16},
            "raw_result": {
                "relations": [{"object": "bottle", "relation": "moved_away_from", "target": "shelf"}],
                "object_masks": [{"object_name": "bottle", "fixture": "shelf", "frame_number": 1200}],
                "count": 2,
            },
        },
    ]

    result = verifier.verify(state=state)

    target_gap = next(item for item in result.evidence_gaps if item["gap_type"] == "target_discovery")
    assert target_gap["target_object"] == "jar"
    assert target_gap["target_fixture"] == "shelf"
    assert "jar" in str(target_gap["missing_observation"]).lower() or "shelf" in str(target_gap["missing_observation"]).lower()


