def test_verifier_action_intent_hypothesis_close_call_blocks_finish_even_without_explicit_missing() -> None:
    verifier = GraphAgentVerifier()
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
            "to pour water into the pan.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.evidence_bundle = ["type=timeline_event; label=bottle moved aside"]
    state.tool_trace = [
        {
            "tool": "resolve_action_intent_future_use",
            "raw_result": {
                "best_index": 1,
                "second_best_index": 0,
                "confidence": 0.88,
                "decisive_observation": "the bottle is carried toward the fridge area",
                "reason": "return-to-fridge looks slightly more likely than immediate label checking",
                "candidate_evidence": [
                    {"index": 1, "score": 0.88},
                    {"index": 0, "score": 0.82},
                    {"index": 2, "score": 0.12},
                ],
            },
        }
    ]

    result = verifier.verify(state=state)

    assert result.sufficient is False
    assert "need_disambiguating_evidence" in result.missing_evidence_types
    assert result.sufficiency_decision["finish_mode"] == "needs_more_evidence"
    assert result.sufficiency_decision["blocking_comparisons"] == []
    assert not any(
        isinstance(item, str) and item.startswith("candidate:")
        for item in result.sufficiency_decision["blocking_hypotheses"]
    )
    assert not any(
        isinstance(item, str) and item.startswith("comparison:")
        for item in result.sufficiency_decision["blocking_hypotheses"]
    )


def test_verifier_sufficiency_decision_treats_structured_blocking_comparison_as_needs_more_evidence_without_explicit_gap() -> None:
    verifier = GraphAgentVerifier()
    decision = verifier._build_sufficiency_decision(  # noqa: SLF001
        state=None,
        sufficient=False,
        missing=[],
        conflicts=[],
        recommend_next_action="",
        summary="close call remains",
        evidence_gaps=[],
        action_intent_hypotheses=[
            {
                "choice_index": 1,
                "choice_text": "to put the bottle back in the fridge.",
                "score": 0.66,
                "comparison_summary": "runner-up still plausible",
                "comparison": {
                    "leading_choice_index": 1,
                    "runner_up_choice_index": 0,
                    "score_gap": 0.03,
                    "unresolved_evidence": "need later evidence showing whether the bottle is returned or only inspected",
                },
            },
            {
                "choice_index": 0,
                "choice_text": "to check the label.",
                "score": 0.63,
            },
        ],
    )

    assert decision["finish_mode"] == "finish_insufficient_evidence"
    assert decision["blocking_comparisons"] == []
    assert not any(
        isinstance(item, str) and item.startswith("candidate:")
        for item in decision["blocking_hypotheses"]
    )


