def test_executor_records_ocr_conflict_hint_before_verifier(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph([], [])

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    executor = GraphAgentExecutor(toolbox, GraphAgentPlanner(DummyClient()), GraphAgentVerifier())
    state = AgentState(video_id="vid", question="What is the reading?", choices=["10 g", "20 g"], task_family="ingredient_ingredient_weight")
    state.evidence_bundle = ["ocr_reading=10 g"]
    state.working_memory = ["ocr_reading=10 g"]
    executor._merge_result_into_state(state, "run_ocr_on_image", {"reading": "20 g", "text": "20 g", "artifact_path": "/tmp/scale.jpg"})
    assert any(item == "conflict:conflicting_ocr_readings" for item in state.open_questions)
    assert any(item.startswith("conflict_hint type=conflicting_ocr_readings") for item in state.working_memory)


