def test_executor_skips_explicit_write_tool_when_conflict_exists(tmp_path: Path) -> None:
    store = GraphMemoryStore(tmp_path / "graph_memory" / "vid")
    store.replace_graph([], [])

    class DummyPlanner:
        def next_action(self, *, state, tool_schemas, hints):
            if state.current_step == 0:
                return PlannerDecision(
                    thought="写入 OCR 读数。",
                    tool="write_ocr_reading",
                    args={
                        "label": "ocr reading",
                        "reading": "20 g",
                        "time_s": 10.0,
                        "image_path": "/tmp/scale_10.000s.jpg",
                    },
                )
            return PlannerDecision(
                thought="结束。",
                tool="finish",
                args={"prediction": 0, "answer": "0", "confidence": 0.9},
                done=True,
                answer="0",
                prediction=0,
                confidence=0.9,
            )

    class DummyClient:
        pass

    paths = ProjectPaths.from_env()
    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="vid")
    executor = GraphAgentExecutor(toolbox, DummyPlanner(), GraphAgentVerifier())
    state = AgentState(video_id="vid", question="What is the reading?", choices=["10 g", "20 g"], task_family="ingredient_ingredient_weight")
    state.open_questions = ["conflict:conflicting_ocr_readings"]
    toolbox.finish = lambda **kwargs: kwargs
    executor.execute(state)
    assert any(item.startswith("writeback_skipped type=ocr_reading") for item in state.working_memory)
    assert any(isinstance(item, dict) and item.get("tool") == "write_ocr_reading" for item in state.tool_trace)
    assert not store.query_nodes(video_id="vid", node_types=["ocr_reading"], limit=5)


