def test_graph_agent_reuses_same_video_session(monkeypatch) -> None:
    paths = ProjectPaths.from_env()

    class MockClient:
        def complete_json(self, messages, temperature=0.0):
            return {"tool": "finish", "args": {"prediction": 0, "answer": "0", "confidence": 0.9}, "done": True}

        def complete(self, messages, temperature=0.0):
            return ModelResponse(content="0", raw={})

    class DummySession:
        def __init__(self, *, agent, video_id):
            self.agent = agent
            self.video_id = video_id
            self.calls = 0

        def answer_vqa_row(self, row, max_steps=6):
            self.calls += 1
            return GraphAgentResult(
                vqa_id=str(row["vqa_id"]),
                video_id=self.video_id,
                task_family=str(row["task_family"]),
                prediction=0,
                answer_text="0",
                evidence_bundle=[],
                tool_trace=[],
                raw_model_output="0",
                working_memory=[],
                retrieved_frames=[],
                visited_times=[],
                artifacts=[],
                confidence=0.9,
                elapsed_seconds=0.01,
            )

    monkeypatch.setattr("food_agent.agent.graph_agent.GraphAgentVideoSession", DummySession)
    agent = GraphAgent(paths=paths, model_client=MockClient())
    row1 = {
        "vqa_id": "a",
        "task_family": "recipe_step_recognition",
        "primary_video_id": "vid1",
        "question": "q1",
        "choices_json": '["0"]',
        "correct_idx": 0,
        "inputs_json": "{}",
    }
    row2 = dict(row1)
    row2["vqa_id"] = "b"
    result1 = agent.answer_vqa_row(row1, max_steps=3)
    result2 = agent.answer_vqa_row(row2, max_steps=3)
    assert result1.video_id == "vid1"
    assert result2.video_id == "vid1"
    assert len(agent._video_sessions) == 1
    assert agent._video_sessions["vid1"].calls == 2


def test_graph_agent_routes_open_query_through_same_video_session(monkeypatch) -> None:
    paths = ProjectPaths.from_env()

    class MockClient:
        def complete_json(self, messages, temperature=0.0):
            return {"tool": "finish", "args": {"prediction": 0, "answer": "0", "confidence": 0.9}, "done": True}

        def complete(self, messages, temperature=0.0):
            return ModelResponse(content="answer", raw={})

    class DummySession:
        def __init__(self, *, agent, video_id):
            self.agent = agent
            self.video_id = video_id
            self.vqa_calls = 0
            self.open_calls = 0

        def answer_vqa_row(self, row, max_steps=6):
            self.vqa_calls += 1
            return GraphAgentResult(
                vqa_id=str(row["vqa_id"]),
                video_id=self.video_id,
                task_family=str(row["task_family"]),
                prediction=0,
                answer_text="0",
                evidence_bundle=[],
                tool_trace=[],
                raw_model_output="0",
                working_memory=[],
                retrieved_frames=[],
                visited_times=[],
                artifacts=[],
                confidence=0.9,
                elapsed_seconds=0.01,
            )

        def answer_open_query(self, *, question, inputs_json="{}", task_family="open_query", max_steps=6, query_id=""):
            self.open_calls += 1
            return GraphAgentResult(
                vqa_id=query_id or "open_query:vid1:test",
                video_id=self.video_id,
                task_family=task_family,
                prediction=None,
                answer_text="freeform answer",
                evidence_bundle=["type=timeline_event; label=stirring"],
                tool_trace=[{"tool": "query_time"}],
                raw_model_output="freeform answer",
                working_memory=["reuse:type=timeline_event"],
                retrieved_frames=[],
                visited_times=[],
                artifacts=[],
                confidence=0.8,
                elapsed_seconds=0.02,
            )

