    agent = GraphAgent(paths=paths, model_client=MockClient())
    result = agent.answer_open_query(video_id="vid1", question="What happened after the onion was added?", max_steps=3)
    assert result.video_id == "vid1"
    assert result.prediction is None
    assert result.answer_text == "freeform answer"
    assert len(agent._video_sessions) == 1
    assert agent._video_sessions["vid1"].open_calls == 1


