def test_agent_state_export_and_restore_session_memory() -> None:
    state = AgentState(
        video_id="vid1",
        question="q",
        choices=["a"],
        task_family="task",
    )
    state.working_memory = ["reuse:type=timeline_event", "ocr_reading=98 g"]
    state.evidence_bundle = ["type=timeline_event; label=stirring"]
    state.retrieved_frames = ["/tmp/a.jpg"]
    state.retrieved_node_ids = ["node-1"]
    state.retrieved_nodes = [{"node_id": "node-1", "node_type": "timeline_event"}]
    state.hypotheses = ["maybe salt"]
    state.open_questions = ["need local region"]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.3,
            "missing_evidence_types": ["need_ocr_reading"],
            "conflicts": [],
            "recommend_next_action": "need_ocr_reading",
            "summary": "missing ocr",
        }
    ]
    state.action_intent_hypotheses = [{"choice_index": 0, "choice_text": "a"}]
    state.final_metadata = {"finish_reason": "needs_more_evidence"}
    state.confidence = 0.7
    payload = state.export_session_memory()

    restored = AgentState(
        video_id="vid1",
        question="q2",
        choices=["b"],
        task_family="task",
    )
    restored.restore_session_memory(payload)
    assert restored.working_memory == ["reuse:type=timeline_event", "ocr_reading=98 g"]
    assert restored.evidence_bundle == ["type=timeline_event; label=stirring"]
    assert restored.retrieved_frames == ["/tmp/a.jpg"]
    assert restored.retrieved_node_ids == ["node-1"]
    assert restored.hypotheses == ["maybe salt"]
    assert restored.open_questions == ["need local region"]
    assert restored.verification_history[0]["recommend_next_action"] == "need_ocr_reading"
    assert restored.action_intent_hypotheses == []
    assert restored.final_metadata == {}
    assert restored.confidence == 0.7


