def test_agent_state_record_verification_writes_action_intent_trace_to_working_memory() -> None:
    state = AgentState(
        video_id="vid1",
        question="q",
        choices=["a", "b"],
        task_family="fine_grained_why_recognition",
    )
    state.record_verification(
        sufficient=False,
        confidence=0.41,
        missing_evidence_types=["need_disambiguating_evidence"],
        conflicts=[],
        recommend_next_action="need_disambiguating_evidence",
        summary="still insufficient",
        sufficiency_decision={
            "sufficient": False,
            "missing_gap_types": ["future_outcome"],
            "blocking_hypotheses": ["candidate:to weigh the bowl"],
            "blocking_comparisons": [
                {
                    "runner_up_choice_index": 0,
                    "runner_up_choice_text": "to empty the bowl",
                    "score_gap": 0.07,
                    "unresolved_evidence": "whether the bowl is placed on the scale right after being picked up",
                }
            ],
            "recommended_next_step": "need_disambiguating_evidence",
            "finish_mode": "needs_more_evidence",
            "summary": "still insufficient",
        },
        action_intent_hypotheses=[
            {
                "choice_index": 1,
                "choice_text": "to weigh the bowl",
                "support_evidence": ["the bowl appears near the scale"],
                "contradiction_evidence": [],
                "missing_observations": ["whether the bowl is placed on the scale right after being picked up"],
                "comparison_summary": "runner-up still plausible with score_gap=0.07 until the scale placement is confirmed",
                "score": 0.73,
                "confidence": 0.73,
            },
            {
                "choice_index": 0,
                "choice_text": "to empty the bowl",
                "support_evidence": ["the bowl is tilted"],
                "contradiction_evidence": [],
                "missing_observations": ["whether contents are poured out"],
                "score": 0.66,
                "confidence": 0.66,
            },
        ],
    )

    assert not any(item.startswith("action_intent_top_hypothesis=") for item in state.working_memory)
    assert not any(item.startswith("action_intent_runner_up=") for item in state.working_memory)
    assert not any(item.startswith("action_intent_top_missing_observation=") for item in state.working_memory)
    assert not any(item.startswith("action_intent_comparison_summary=") for item in state.working_memory)
    assert not any(item.startswith("action_intent_blocking_comparison=") for item in state.working_memory)


