def test_planner_uses_verifier_history_to_prioritize_missing_evidence() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise RuntimeError("force heuristic fallback")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What is the reading on the scale? <TIME 00:00:10.000 video 1> <TIME 00:00:12.000 video 1>",
        choices=["10 g", "20 g"],
        task_family="ingredient_ingredient_weight",
    )
    state.open_questions = ["need_ocr_reading", "need_time_localization"]
    state.retrieved_frames = ["/tmp/frame.jpg"]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.35,
            "missing_evidence_types": ["need_ocr_reading"],
            "conflicts": [],
            "recommend_next_action": "need_ocr_reading",
            "summary": "still missing ocr",
        }
    ]
    decision = planner.next_action(
        state=state,
        tool_schemas=[],
        hints={"times": [10.0, 12.0], "input_times": [], "bbox": None, "ingredient_name": "onions", "ocr_keyword": "reading"},
    )
    assert decision.tool in {"run_ocr_on_image", "query_ocr"}
    assert any("candidate_plan_selected tool=" in item for item in state.working_memory)
    assert any("verifier 明确指出" in item for item in state.hypotheses if item.startswith("candidate_plan_rationale="))


