def test_planner_prefers_expand_graph_context_when_anchor_nodes_exist() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise RuntimeError("force heuristic fallback")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What is the reading on the scale? <TIME 00:00:10.000 video 1> <TIME 00:00:12.000 video 1>",
        choices=["10 g", "20 g"],
        task_family="ingredient_ingredient_weight",
    )
    state.open_questions = ["need_ocr_reading"]
    state.retrieved_node_ids = ["timeline:vid:step1"]
    state.retrieved_nodes = [{"node_id": "timeline:vid:step1", "node_type": "timeline_event"}]
    decision = planner.next_action(
        state=state,
        tool_schemas=[],
        hints={"times": [10.0, 12.0], "input_times": [], "bbox": None, "ingredient_name": "onions", "ocr_keyword": "reading"},
    )
    assert decision.tool == "expand_graph_context"
    assert decision.args["node_ids"] == ["timeline:vid:step1"]


