def test_planner_open_query_temporal_summary_recovery_uses_peak_frames_after_audio_detection() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise RuntimeError("force heuristic fallback")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What happened after the onion was added? <TIME 00:00:10.000 video 1> <TIME 00:00:16.000 video 1>",
        choices=["OPEN_ENDED_RESPONSE"],
        task_family="open_query_temporal_summary",
    )
    state.open_questions = ["need_time_localization", "need_initial_observation"]
    state.tool_trace = [{"tool": "detect_audio_peaks", "raw_result": {"peaks": [{"time_s": 11.0}, {"time_s": 14.5}]}}]
    decision = planner._audio_peak_followup_decision(
        state=state,
        used_tools=["detect_audio_peaks"],
        combined_times=[10.0, 16.0],
        last_tool=state.tool_trace[-1],
        last_result=state.tool_trace[-1]["raw_result"],
    )
    assert decision.tool == "sample_frames_around_peaks"
    assert decision.args["peak_times"] == [11.0, 14.5]


