def test_planner_open_query_verifier_blocked_finish_prefers_raw_grounding() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            return {
                "thought": "先结束。",
                "tool": "finish",
                "args": {"prediction": 0, "answer": "0", "confidence": 0.7},
                "done": True,
                "confidence": 0.7,
            }

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What happened after the onion was added? <TIME 00:00:10.000 video 1> <TIME 00:00:12.000 video 1>",
        choices=["OPEN_ENDED_RESPONSE"],
        task_family="open_query_temporal_summary",
    )
    state.open_questions = ["need_disambiguating_evidence", "need_initial_observation"]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.35,
            "missing_evidence_types": ["need_disambiguating_evidence", "need_initial_observation"],
            "conflicts": [],
            "recommend_next_action": "need_initial_observation",
            "summary": "still missing grounded observation",
        }
    ]
    decision = planner.next_action(
        state=state,
        tool_schemas=[],
        hints={"times": [10.0, 12.0], "input_times": [], "bbox": None, "ingredient_name": None},
    )
    assert decision.tool == "sample_sparse_frames"
    assert any(item.startswith("planner_override verifier_blocked_finish=finish -> sample_sparse_frames") for item in state.working_memory)


