def test_planner_action_intent_verifier_blocked_text_fallback_prefers_cached_segment_artifacts() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise AssertionError("heuristic planning should avoid model call")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move sponge> in video 1?",
        choices=[
            "so that I can lift the chop board and take the chop board to the sink.",
            "to remove coffee residue from the cup.",
            "to rinse the sponge while holding the white chop board in hand.",
            "so that the sink drainage is not covered by the sponge and the brush.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.current_step = 4
    state.max_steps = 8
    state.open_questions = ["need_alternative_evidence_path", "need_disambiguating_evidence"]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.41,
            "missing_evidence_types": ["need_alternative_evidence_path", "need_disambiguating_evidence"],
            "conflicts": [],
            "recommend_next_action": "need_alternative_evidence_path",
            "summary": "text fallback not enough",
        }
    ]
    state.artifacts = ["/tmp/fine_grained_why_recognition_segment_528.139s.jpg"]
    state.retrieved_frames = ["/tmp/fine_grained_why_recognition_segment_528.139s.jpg"]
    state.tool_trace = [
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "rank_choices_from_state", "raw_result": {"best_index": 2, "confidence": 0.76}},
    ]

    decision = planner._recover_from_open_questions(
        state=state,
        hints={"times": [528.139, 529.620], "input_times": [], "bbox": None},
        used_tools=["infer_action_intent", "rank_choices_from_state"],
    )

    assert decision.tool in {
        "retrieve_cached_artifacts",
        "sample_sparse_frames",
        "resolve_action_intent_future_use",
    }
    if decision.tool == "retrieve_cached_artifacts":
        assert decision.args["tag_hint"] == "fine_grained_why_recognition_segment"


