def test_planner_action_intent_before_text_fallback_explicit_downstream_object_prefers_primary_gap_over_specialized_resolution() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move bottle> in video 1?",
        choices=[
            "to make space on the shelf.",
            "so that I can take the spice jar from the shelf.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.retrieved_frames = [
        "/tmp/fine_grained_why_recognition_segment_000_140.000s.jpg",
        "/tmp/fine_grained_why_recognition_segment_001_144.200s.jpg",
    ]
    planner._action_intent_primary_gap = lambda _state: {  # type: ignore[method-assign]
        "gap_type": "future_outcome",
        "target_object": "jar",
        "target_fixture": "shelf",
    }
    planner._recover_action_intent_via_primary_gap = lambda **kwargs: PlannerDecision(  # type: ignore[method-assign]
        thought="primary gap recovery before text fallback",
        tool="query_object",
        args={"query": "jar", "limit": 24},
    )
    planner._build_action_intent_future_use_resolution_decision = lambda **kwargs: PlannerDecision(  # type: ignore[method-assign]
        thought="specialized recovery that should yield to gap route before text fallback",
        tool="resolve_action_intent_future_use",
        args={"question": state.question, "choices": state.choices},
    )

    decision = planner._build_action_intent_specialized_resolution_before_text_fallback(  # noqa: SLF001
        state=state,
        hints={"times": [140.0, 144.2], "input_times": [], "bbox": None},
    )

    assert decision is not None
    assert decision.tool == "query_object"
    assert decision.args["query"] == "jar"
    assert any(
        item.startswith("planner_guard=before_text_fallback_prefers_primary_gap=query_object")
        for item in state.working_memory
    )


