def test_planner_infer_action_intent_provider_level_failure_skips_visual_retry_and_prefers_state_candidate() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move bottle> in video 1?",
        choices=[
            "to make space on the shelf.",
            "so that I can take the spice jar from the shelf.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.retrieved_frames = [
        "/tmp/fine_grained_why_recognition_segment_000_140.000s.jpg",
        "/tmp/fine_grained_why_recognition_segment_001_144.200s.jpg",
    ]
    state.tool_trace = [
        {
            "tool": "infer_action_intent",
            "raw_result": {
                "tool_failed": True,
                "error_type": "RuntimeError",
                "error_message": "vision request failed after 1 attempts for model=gpt-5.4: Error code: 503 - {'error': {'code': 'model_not_found', 'message': 'No available channel for model gpt-5.4', 'type': 'new_api_error'}}",
            },
        }
    ]
    planner._best_state_candidate_plan = lambda **kwargs: CandidatePlan(  # type: ignore[method-assign]
        decision=PlannerDecision(
            thought="gap-routed object query after provider-level visual failure",
            tool="query_object",
            args={"query": "jar", "limit": 24},
        ),
        cost=1,
        gain=5,
        risk=0,
            rationale="provider-level visual failure should defer to gap-aware candidate",
        )
    planner._build_action_intent_specialized_recovery_decision = lambda **kwargs: PlannerDecision(  # type: ignore[method-assign]
        thought="specialized visual retry that should be skipped",
        tool="infer_action_intent",
        args={"question": state.question, "choices": state.choices},
    )
    planner._should_continue_search_from_sufficiency = lambda _state: True  # type: ignore[method-assign]

    decision = planner._heuristic_fallback(  # noqa: SLF001
        state=state,
        hints={"times": [140.0, 144.2], "input_times": [], "bbox": None},
    )

    assert decision.tool == "query_object"
    assert decision.args["query"] == "jar"
    assert "planner_guard=infer_action_intent_provider_failure_skips_visual_retry=1" in state.working_memory
    assert any(
        item.startswith("planner_guard=infer_failures_prefers_state_candidate=query_object")
        for item in state.working_memory
    )


