def test_planner_resolution_payload_continue_search_prefers_state_candidate_over_generic_recovery() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.tool_trace = [
        {
            "tool": "resolve_action_intent_future_use",
            "raw_result": {
                "best_index": 1,
                "answer": "to put the bottle back in the fridge.",
                "confidence": 0.83,
                "decisive_observation": "the bottle is later seen near the fridge",
                "reason": "the later frames suggest fridge-related use but do not fully settle the final placement",
                "need_more_evidence": False,
            },
        }
    ]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.41,
            "missing_evidence_types": [],
            "conflicts": [],
            "recommend_next_action": "",
            "summary": "still insufficient",
            "evidence_gaps": [],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["candidate:to put the bottle back in the fridge."],
                "blocking_comparisons": [],
                "recommended_next_step": "",
                "finish_mode": "needs_more_evidence",
                "summary": "still insufficient",
            },
        }
    ]
    calls = {"count": 0}

    def fake_recover_from_open_questions(**kwargs):  # type: ignore[no-untyped-def]
        calls["count"] += 1
        if calls["count"] == 1:
            return PlannerDecision(
                thought="first recovery pass stays on specialized branch",
                tool="rank_choices_from_state",
                args={"question": state.question, "choices": state.choices},
            )
        return PlannerDecision(
            thought="generic open-question recovery",
            tool="retrieve_cached_artifacts",
            args={"prefixes": ["fine_grained_why_recognition_followup"]},
        )

    planner._recover_from_open_questions = fake_recover_from_open_questions  # type: ignore[method-assign]
    candidate_calls = {"count": 0}

    def fake_best_state_candidate_plan(**kwargs):  # type: ignore[no-untyped-def]
        candidate_calls["count"] += 1
        if candidate_calls["count"] == 1:
            return None
        return CandidatePlan(
            decision=PlannerDecision(
                thought="targeted fridge follow-up",
                tool="query_spatial_context",
                args={"object_name": "fridge", "time_s": 53.0, "limit": 8},
            ),
            cost=1,
            gain=5,
            risk=1,
            rationale="structured future-outcome gap points to the fridge as the decisive downstream target",
        )

    planner._best_state_candidate_plan = fake_best_state_candidate_plan  # type: ignore[method-assign]
    planner._action_intent_primary_gap = lambda _state: None  # type: ignore[method-assign]
    planner._action_intent_resolution_should_backfill_precondition = lambda **kwargs: False  # type: ignore[method-assign]
    planner._build_action_intent_finalize_withheld_generic_access_or_space_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_finalize_withheld_mixed_horizon_later_target_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_finalize_withheld_generic_relocation_or_storage_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_unresolved_rerank_downstream_fixture_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_unresolved_rerank_downstream_target_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_unresolved_rerank_mixed_horizon_later_target_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_unresolved_rerank_long_horizon_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_resolution_transition_recovery_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_weak_late_anchor_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_nonexclusive_concrete_late_anchor_revisit_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._build_action_intent_peak_guided_followup_decision = lambda **kwargs: None  # type: ignore[method-assign]
    planner._action_intent_resolution_needs_more_evidence = lambda **kwargs: False  # type: ignore[method-assign]
    planner._action_intent_result_is_weak_generic_claim = lambda **kwargs: False  # type: ignore[method-assign]
    planner._action_intent_result_is_workspace_or_final_placement_close_call = lambda **kwargs: False  # type: ignore[method-assign]
    planner._action_intent_resolution_payload_is_ready_to_finish = lambda **kwargs: True  # type: ignore[method-assign]
    planner._action_intent_primary_gap = lambda _state: None  # type: ignore[method-assign]
    planner._action_intent_structured_specialized_recovery_tool = lambda _state: ""  # type: ignore[method-assign]
    sufficiency_calls = {"count": 0}

    def fake_should_continue_search_from_sufficiency(_state):  # type: ignore[no-untyped-def]
        sufficiency_calls["count"] += 1
        return sufficiency_calls["count"] >= 2

    planner._should_continue_search_from_sufficiency = fake_should_continue_search_from_sufficiency  # type: ignore[method-assign]

    decision = planner._heuristic_fallback(  # noqa: SLF001
        state=state,
        hints={"times": [50.0, 51.0], "input_times": [], "bbox": None},
    )

    assert decision.tool == "query_spatial_context"
    assert decision.args["object_name"] == "fridge"
    assert calls["count"] >= 2
    assert candidate_calls["count"] >= 2
    assert any(
        item.startswith(
            "planner_guard=resolution_payload_prefers_state_candidate_over_generic_recovery="
        )
        for item in state.working_memory
    )


