    assert "/tmp/open_query_temporal_summary_010.800s.jpg" in state.artifacts
    assert 10.8 in state.visited_times
    assert any(item.startswith("cached_artifact_count=1") for item in state.working_memory)
    written = store.query_nodes(video_id="vid", node_types=["observation"], keyword="cached artifact reuse", limit=10)
    assert written


