def test_agent_toolbox_infer_named_fixture_direction_prefers_spatial_context_before_vision() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P01-20240202-161948")

    class DummyClient:
        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            raise AssertionError("structured spatial path should avoid vision request")

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="P01-20240202-161948")
    result = toolbox.infer_named_fixture_direction(
        question="Given the direction I am looking at <TIME 00:00:27.2 video 1>, where is the boiler located?",
        choices=["6 o'clock", "10 o'clock", "1 o'clock", "3 o'clock", "9 o'clock"],
        image_paths=["/tmp/a.jpg", "/tmp/b.jpg", "/tmp/c.jpg"],
        spatial_context={
            "object_masks": [
                {
                    "fixture": "P01_hob.001",
                    "bbox_json": "[314.947, 849.895, 673.895, 1062.947]",
                    "frame_distance": 20.0,
                },
                {
                    "fixture": "P01_counter.002",
                    "bbox_json": "[729.474, 866.105, 831.368, 949.474]",
                    "frame_distance": 318.0,
                },
            ]
        },
    )
    assert result["target_match"] == "P01_hob.001"
    assert result["best_index"] == 1
    assert result["answer"] == "10 o'clock"


