def test_agent_toolbox_infer_temporal_localization_choice_refines_fine_grained_action_windows() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P04-20240415-175615")

    class DummyClient:
        def __init__(self):
            self.calls = 0

        def inspect_images(self, *, prompt, image_paths, temperature=0.0):
            self.calls += 1

            class Response:
                def __init__(self, content):
                    self.content = content

            if self.calls == 1:
                return Response(
                    json.dumps(
                        {
                            "best_index": 0,
                            "answer": "choice-0",
                            "confidence": 0.72,
                            "reason": "coarse temporal comparison prefers choice 0",
                        }
                    )
                )
            per_choice = {
                0: {"score": 0.58, "matches": True, "reason": "brief adjustment but not the clearest reposition window"},
                1: {"score": 0.37, "matches": False, "reason": "starting cut/root trimming"},
                2: {"score": 0.42, "matches": False, "reason": "knife poised but still mainly preparing"},
                3: {"score": 0.91, "matches": True, "reason": "onion is clearly rotated and reset before next cut"},
                4: {"score": 0.51, "matches": False, "reason": "ongoing trimming rather than reposition"},
            }
            for idx, payload in per_choice.items():
                if f"当前候选: choice-{idx}" in prompt:
                    return Response(json.dumps(payload))
            raise AssertionError(f"unexpected prompt: {prompt}")

        def _extract_json_object(self, text):
            return json.loads(text)

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="P04-20240415-175615")

    captured_frames_per_choice: list[int] = []

    def fake_sample_choice_frames(*, choice_index, choices, frames_per_choice=3, tag="choice"):
        captured_frames_per_choice.append(frames_per_choice)
        return {"artifact_paths": [f"/tmp/choice_{choice_index}.jpg"], "choice_index": choice_index}

    def fake_build_temporal_localization_prompt(*, question, choices, task_family, choice_groups):
        return "coarse_temporal_prompt"

    toolbox.sample_choice_frames = fake_sample_choice_frames  # type: ignore[method-assign]
    toolbox._build_temporal_localization_prompt = fake_build_temporal_localization_prompt  # type: ignore[method-assign]

    result = toolbox.infer_temporal_localization_choice(
        question="When did the action <reposition onion> happen in the video 1?",
        choices=["choice-0", "choice-1", "choice-2", "choice-3", "choice-4"],
        task_family="fine_grained_action_localization",
    )
    assert result["best_index"] == 3
    assert result["answer"] == "choice-3"
    assert "temporal_refine_override" in result["reason"]
    assert "per_choice_scores" in result["reason"]
    assert captured_frames_per_choice and all(value >= 3 for value in captured_frames_per_choice)


