def test_agent_toolbox_sample_choice_frames_uses_video_labels_from_inputs_json() -> None:
    paths = ProjectPaths.from_env()
    store = GraphMemoryStore(paths.graph_memory_root / "P06-20240510-104642")

    class DummyClient:
        pass

    toolbox = AgentToolbox(store=store, paths=paths, model_client=DummyClient(), video_id="P06-20240510-104642")
    toolbox.set_runtime_context(
        question="When did the participant perform prep?",
        inputs_json='{"video 1": {"id": "P06-20240510-104642"}, "video 2": {"id": "P06-20240510-115307"}}',
    )

    called_paths: list[str] = []

    def fake_video_path_for(video_id: str):
        return Path(f"/tmp/{video_id}.mp4")

    class FakeVideoOps:
        @staticmethod
        def extract_frames_for_range(*, video_path, start_time, end_time, stride_s, max_frames, prefix):
            called_paths.append(str(video_path))
            return [Path(f"/tmp/{prefix}_0.jpg"), Path(f"/tmp/{prefix}_1.jpg")]

        @staticmethod
        def extract_frame_at_time(*, video_path, time_s, output_name):
            called_paths.append(str(video_path))
            return Path(f"/tmp/{output_name}")

    toolbox._video_path_for = fake_video_path_for  # type: ignore[method-assign]
    toolbox.video = FakeVideoOps()  # type: ignore[assignment]

    result = toolbox.sample_choice_frames(
        choice_index=0,
        choices=["<TIME 00:00:35.743 video 2> to <TIME 00:05:29.497 video 2>"],
        frames_per_choice=2,
        tag="multi_video_choice",
    )
    assert result["artifact_paths"]
    assert result["sources"][0]["video_id"] == "P06-20240510-115307"
    assert any(path.endswith("P06-20240510-115307.mp4") for path in called_paths)


