def test_planner_guards_against_none_heuristic_decision_for_object_motion(monkeypatch) -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise AssertionError("heuristic object-motion planning should avoid model call")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="How many times did this object move?",
        choices=["6", "7", "5", "1", "3"],
        task_family="object_motion_object_movement_counting",
    )
    state.current_step = 1

    def broken_heuristic(*, state, hints):
        return None

    monkeypatch.setattr(planner, "_heuristic_fallback", broken_heuristic)
    decision = planner.next_action(
        state=state,
        tool_schemas=[],
        hints={"times": [81.733], "input_times": [], "bbox": [0.1, 0.1, 0.3, 0.3]},
    )
    assert decision is not None
    assert decision.tool in {"resolve_bbox_reference", "query_time", "rank_choices_from_state"}


