def test_planner_generic_cached_artifact_candidate_overrides_new_frame_sampling() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            return {
                "thought": "先抽帧看看。",
                "tool": "sample_sparse_frames",
                "args": {"start_time": 10.0, "end_time": 14.0, "num_frames": 6, "tag": "tmp"},
                "done": False,
                "confidence": 0.4,
            }

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What happened after the onion was added? <TIME 00:00:10.000 video 1> <TIME 00:00:12.000 video 1>",
        choices=["OPEN_ENDED_RESPONSE"],
        task_family="open_query_temporal_summary",
    )
    state.open_questions = ["need_initial_observation", "need_disambiguating_evidence"]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.2,
            "missing_evidence_types": ["need_initial_observation"],
            "conflicts": [],
            "recommend_next_action": "need_initial_observation",
            "summary": "missing direct grounded observation",
        }
    ]
    state.artifacts = ["/tmp/open_query_temporal_summary_010.800s.jpg"]
    state.visited_times = [10.8]
    decision = planner.next_action(
        state=state,
        tool_schemas=[],
        hints={"times": [10.0, 12.0], "input_times": [], "bbox": None},
    )
    assert decision.tool == "retrieve_cached_artifacts"
    assert decision.args["tag_hint"] == "open_query_temporal_summary"
    assert decision.args["time_s"] == 10.8
    assert any(
        "planner_override cheaper_raw_grounding=sample_sparse_frames -> retrieve_cached_artifacts" in item
        for item in state.working_memory
    )


