def test_planner_action_intent_followup_window_expands_with_window_level() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise AssertionError("heuristic planning should avoid model call")

    planner = GraphAgentPlanner(DummyClient())
    base_state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move glass> in video 1?",
        choices=["avoid heat", "access what's behind a glass", "make space"],
        task_family="fine_grained_why_recognition",
    )
    base_state.working_memory = ["action_intent_followup_gap=1 window_s=4.0 focus=disambiguate access-vs-space"]

    level0 = AgentState(**base_state.__dict__ | {"search_budget": {"window_level": 0}})
    level1 = AgentState(**base_state.__dict__ | {"search_budget": {"window_level": 1}})
    level2 = AgentState(**base_state.__dict__ | {"search_budget": {"window_level": 2}})

    decision0 = planner._build_action_intent_followup_sampling_decision(  # noqa: SLF001
        state=level0,
        hints={"times": [], "input_times": [1560.21, 1561.81], "bbox": None},
    )
    decision1 = planner._build_action_intent_followup_sampling_decision(  # noqa: SLF001
        state=level1,
        hints={"times": [], "input_times": [1560.21, 1561.81], "bbox": None},
    )
    decision2 = planner._build_action_intent_followup_sampling_decision(  # noqa: SLF001
        state=level2,
        hints={"times": [], "input_times": [1560.21, 1561.81], "bbox": None},
    )

    assert decision0 is not None and decision1 is not None and decision2 is not None
    width0 = decision0.args["end_time"] - decision0.args["start_time"]
    width1 = decision1.args["end_time"] - decision1.args["start_time"]
    width2 = decision2.args["end_time"] - decision2.args["start_time"]
    assert width1 >= width0
    assert width2 >= width1
    assert decision1.args["sample_count"] >= decision0.args["sample_count"]
    assert decision2.args["sample_count"] >= decision1.args["sample_count"]


