    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move bowl> in video 1?",
        choices=[
            "to make space.",
            "to access what is behind the bowl.",
            "to put the bowl away.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.tool_trace = [
        {
            "tool": "infer_action_intent",
            "raw_result": {
                "best_index": 0,
                "answer": "to make space.",
                "confidence": 0.71,
                "second_best_index": 1,
                "candidate_indices": [0, 1, 2],
                "need_future_evidence": False,
                "need_more_evidence": False,
                "ambiguity": False,
                "reason": "the bowl is resting on the counter after the movement.",
            },
        }
    ]

    planner._action_intent_requires_followup = lambda *_args, **_kwargs: False  # type: ignore[method-assign]
    planner._action_intent_pair_needs_outcome_resolution = lambda *_args, **_kwargs: False  # type: ignore[method-assign]
    planner._action_intent_needs_future_use_evidence = lambda *_args, **_kwargs: False  # type: ignore[method-assign]
    planner._action_intent_needs_precondition_context = lambda *_args, **_kwargs: False  # type: ignore[method-assign]
    planner._action_intent_result_has_direct_post_action_evidence = lambda *_args, **_kwargs: False  # type: ignore[method-assign]
    planner._build_action_intent_followup_sampling_decision = lambda **_kwargs: (_ for _ in ()).throw(  # type: ignore[method-assign]
        AssertionError("candidate uncertainty alone should not trigger initial followup")
    )
    planner._best_state_candidate_plan = lambda **_kwargs: CandidatePlan(  # type: ignore[method-assign]
        decision=PlannerDecision(
            thought="fallback observation-centric plan",
            tool="query_object",
            args={"query": "bowl", "limit": 24},
        ),
        cost=1,
        gain=1,
        risk=0,
        rationale="observation-centric fallback",
    )

    decision = planner._heuristic_fallback(
        state=state,
        hints={"times": [], "input_times": [100.0, 100.5], "bbox": None},
    )

    assert decision.tool == "finish"


