def test_planner_action_intent_followup_route_does_not_bootstrap_from_structured_specialized_tool_without_observation_gap() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.44,
            "missing_evidence_types": [],
            "conflicts": [],
            "recommend_next_action": "",
            "summary": "structured future-outcome close call",
            "action_intent_hypotheses": [
                {"choice_index": 0, "choice_text": "to check the label.", "score": 0.67, "confidence": 0.67},
                {"choice_index": 1, "choice_text": "to put the bottle back in the fridge.", "score": 0.65, "confidence": 0.65},
            ],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["future_outcome"],
                "blocking_comparisons": [
                    {
                        "runner_up_choice_index": 1,
                        "runner_up_choice_text": "to put the bottle back in the fridge.",
                        "score_gap": 0.02,
                        "unresolved_evidence": "whether the bottle is placed back into the fridge later",
                    }
                ],
                "recommended_next_step": "need_alternative_evidence_path",
                "finish_mode": "needs_more_evidence",
                "summary": "still unresolved",
            },
        }
    ]
    state.tool_trace = [
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
    ]
    planner._action_intent_primary_gap = lambda _state: {}  # type: ignore[method-assign]
    planner._action_intent_structured_specialized_recovery_tool = (  # type: ignore[method-assign]
        lambda _state: "resolve_action_intent_future_use"
    )

    needs, reason, window_s, resolver = planner._action_intent_followup_route(  # noqa: SLF001
        state=state,
        result=None,
    )

    assert needs is False
    assert reason == ""
    assert resolver == ""
    assert window_s == 4.0


