def test_planner_action_intent_peak_probe_window_expands_with_window_level() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state_level0 = AgentState(
        video_id="vid",
        question="Why did the person move the object?",
        choices=["a", "b"],
        task_family="fine_grained_why_recognition",
        search_budget={"window_level": 0},
    )
    state_level2 = AgentState(
        video_id="vid",
        question="Why did the person move the object?",
        choices=["a", "b"],
        task_family="fine_grained_why_recognition",
        search_budget={"window_level": 2},
    )
    for state in (state_level0, state_level2):
        state.tool_trace = [
            {
                "tool": "sample_sparse_frames",
                "args": {
                    "start_time": 233.389,
                    "end_time": 241.389,
                    "sample_count": 4,
                    "tag": "fine_grained_why_recognition_followup",
                },
                "raw_result": {},
            },
            {
                "tool": "resolve_action_intent_future_use",
                "raw_result": {
                    "best_index": 1,
                    "answer": "b",
                    "confidence": 0.54,
                    "decisive_observation": "",
                    "reason": "current images are insufficient",
                    "need_more_evidence": True,
                    "needed_observation": "whether the pot is put on the scale or used to pour water",
                    "candidate_indices": [0, 1],
                },
            },
        ]

    window0 = planner._action_intent_peak_probe_window(  # noqa: SLF001
        state=state_level0,
        hints={"times": [], "input_times": [232.65, 233.389]},
    )
    window2 = planner._action_intent_peak_probe_window(  # noqa: SLF001
        state=state_level2,
        hints={"times": [], "input_times": [232.65, 233.389]},
    )

    assert window0 is not None and window2 is not None
    assert window2[1] - window2[0] > window0[1] - window0[0]


