def test_graph_agent_action_intent_unresolved_rerank_prefers_direct_hand_contact_over_counter_cleanup() -> None:
    agent = object.__new__(GraphAgent)
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <pick up paper towel> in video 1?",
        choices=[
            "to move.",
            "to dry hand.",
            "to clean up the kitchen counter.",
            "to wipe both hands.",
            "to dry.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.tool_trace = [
        {
            "tool": "resolve_action_intent_future_use",
            "raw_result": {
                "best_index": 2,
                "answer": "to clean up the kitchen counter.",
                "confidence": 0.66,
                "need_more_evidence": True,
                "candidate_indices": [0, 1, 2, 3, 4],
                "candidate_evidence": [
                    {
                        "index": 0,
                        "support": "The paper towel is picked up and then set down on the counter in a different spot.",
                        "contradiction": "Immediately after pickup, the towel is rubbed against the other hand/fingers rather than being relocated for its own sake. The post-action use is hand contact, not just moving the towel.",
                        "score": 0.18,
                    },
                    {
                        "index": 1,
                        "support": "After picking up the paper towel, the person brings it to the hand area and appears to dab/rub one hand/fingers with it, consistent with drying a hand.",
                        "contradiction": "The frames do not clearly show only one hand being dried; the towel may contact both hands or be used briefly, so the single-hand specificity is limited.",
                        "score": 0.70,
                    },
                    {
                        "index": 2,
                        "support": "The towel is briefly near the counter/appliance area where cleanup could happen.",
                        "contradiction": "There is no clear wiping sweep over the kitchen counter surface or visible spill removal. The towel is used on the hand area, then left on the counter; no actual counter-cleaning result is shown.",
                        "score": 0.08,
                    },
                    {
                        "index": 3,
                        "support": "The towel is held in one hand and brought toward the hands, which could suggest wiping hands.",
                        "contradiction": "The images do not clearly show both hands being wiped thoroughly. Evidence is stronger for a brief dry/wipe of a hand than for both hands specifically.",
                        "score": 0.46,
                    },
                    {
                        "index": 4,
                        "support": "The towel is used in a drying-like manner on the hand area, so a generic drying purpose fits the observed aftermath.",
                        "contradiction": "This is vaguer than 'dry hand' and less directly tied to the observed object being dried. The visible target appears to be the hand(s), not some other object or surface.",
                        "score": 0.62,
                    },
                ],
            },
        }
    ]

    resolved = agent._resolve_deterministic_answer_from_state(state)  # noqa: SLF001

    assert resolved is not None
    assert resolved[0] == 4
    assert resolved[1] == "to dry."


