def test_graph_agent_action_intent_finalizer_allows_resolution_after_new_followup_even_if_old_timeline_review_asked_for_more_evidence() -> None:
    agent = object.__new__(GraphAgent)
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.retrieved_frames = [
        "/tmp/fine_grained_why_recognition_followup_ext2_000_00626.000s.jpg",
    ]
    state.tool_trace = [
        {
            "tool": "inspect_visual_evidence",
            "raw_result": {
                "timeline_summary": "the bottle is carried away from the shelf",
                "next_use_evidence": "it is still not visible whether the bottle is put back or kept out",
                "ambiguity_note": "the final location remains unclear after pickup",
                "needs_more_evidence": True,
                "confidence": 0.55,
            },
        },
        {
            "tool": "sample_sparse_frames",
            "args": {
                "start_time": 621.1,
                "end_time": 629.1,
                "sample_count": 4,
                "tag": "fine_grained_why_recognition_followup_ext2",
            },
            "raw_result": {"artifact_paths": state.retrieved_frames},
        },
        {
            "tool": "resolve_action_intent_future_use",
            "raw_result": {
                "best_index": 1,
                "answer": "to put the bottle back in the fridge.",
                "confidence": 0.9,
                "need_more_evidence": False,
                "second_best_index": 0,
                "reason": "After the new followup frames, the bottle is put back in the fridge.",
                "decisive_observation": "The bottle is returned to the fridge and placed back on the shelf.",
            },
        },
    ]

    resolved = agent._resolve_deterministic_answer_from_state(state)  # noqa: SLF001

    assert resolved is not None
    assert resolved[0] == 1
    assert resolved[1] == "to put the bottle back in the fridge."


