def test_graph_agent_action_intent_unresolved_timeline_review_bias_gaps_ignore_choice_categories() -> None:
    agent = object.__new__(GraphAgent)
    agent._action_intent_has_unresolved_timeline_review_gap = lambda _state: True  # type: ignore[method-assign]
    agent._action_intent_timeline_review_bias_profile = lambda _state: {  # type: ignore[method-assign]
        "has_review": True,
        "needs_more_evidence": True,
        "revealed_target_retrieval": False,
        "revealed_slot_placement": False,
        "revealed_fixture_enablement": False,
        "hand_free_next_action": False,
        "next_use_unclear": True,
        "final_location_unclear": False,
    }
    matching_state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=["to check the label.", "to put the bottle back in the fridge."],
        task_family="fine_grained_why_recognition",
    )
    swapped_state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=["to make the bottle look nicer.", "to put the bottle back in the fridge."],
        task_family="fine_grained_why_recognition",
    )
    candidate_rows = [
        {
            "index": 0,
            "choice": "placeholder",
            "support": "The bottle label becomes visible while the bottle is held in hand.",
            "contradiction": "Whether the person actually reads it next is still not visible.",
            "adjusted_score": 0.31,
        }
    ]

    matching_gaps = agent._action_intent_unresolved_timeline_review_bias_gaps(  # noqa: SLF001
        state=matching_state,
        candidate_rows=candidate_rows,
        best_index=0,
    )
    swapped_gaps = agent._action_intent_unresolved_timeline_review_bias_gaps(  # noqa: SLF001
        state=swapped_state,
        candidate_rows=candidate_rows,
        best_index=0,
    )

    assert "timeline_review_next_use_gap" in matching_gaps
    assert swapped_gaps == matching_gaps


