def test_graph_agent_finalize_recovers_from_text_provider_failure_via_trace_best_index() -> None:
    class FailingClient:
        def complete(self, messages, temperature=0.0):
            raise RuntimeError("model request failed after 4 attempts")

    agent = object.__new__(GraphAgent)
    agent.model_client = FailingClient()
    state = AgentState(
        video_id="vid",
        question="Which option is supported?",
        choices=["first", "second", "third"],
        task_family="visual_mcq",
    )
    state.tool_trace = [
        {"tool": "query_time", "raw_result": {"matches": []}},
        {"tool": "rank_choices_from_state", "raw_result": {"best_index": 2, "confidence": 0.63}},
    ]
    state.verification_history = [
        {
            "sufficient": True,
            "confidence": 0.63,
            "summary": "enough evidence",
            "sufficiency_decision": {
                "sufficient": True,
                "finish_mode": "answer_ready",
                "recommended_next_step": "",
            },
        }
    ]

    answer_text, prediction = agent._finalize_state_answer(state=state, freeform=False)  # noqa: SLF001

    assert prediction == 2
    assert answer_text == "third"
    assert state.final_prediction == 2
    assert state.final_answer == "third"
    assert state.final_metadata["finalize_recovery"] == "trace_best_index"
    assert not any(item.startswith("finalize_text_failure_recovered_by=") for item in state.working_memory)


