def test_planner_action_intent_specialized_resolution_candidate_indices_do_not_bootstrap_from_structured_comparison_pair() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
            "so that I can take the spice jar.",
            "to make more workspace on the counter.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.43,
            "missing_evidence_types": [],
            "conflicts": [],
            "recommend_next_action": "",
            "summary": "structured close call still unresolved",
            "evidence_gaps": [
                {
                    "gap_type": "future_outcome",
                    "priority": "high",
                    "missing_observation": "whether the spice jar is actually taken after the bottle is moved",
                    "target_object": "spice jar",
                    "target_fixture": "",
                    "time_relation": "later_after_action",
                    "source": "verifier",
                }
            ],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["future_outcome"],
                "blocking_comparisons": [
                    {
                        "leading_choice_index": 2,
                        "runner_up_choice_index": 1,
                        "score_gap": 0.03,
                        "unresolved_evidence": "whether the spice jar is actually taken after the bottle is moved or the bottle is just returned",
                    }
                ],
                "recommended_next_step": "need_disambiguating_evidence",
                "finish_mode": "needs_more_evidence",
                "summary": "still insufficient",
            },
            "action_intent_hypotheses": [
                {
                    "choice_index": 2,
                    "choice_text": "so that I can take the spice jar.",
                    "score": 0.66,
                    "confidence": 0.66,
                    "comparison": {
                        "leading_choice_index": 2,
                        "runner_up_choice_index": 1,
                        "unresolved_evidence": "whether the spice jar is actually taken after the bottle is moved or the bottle is just returned",
                    },
                },
                {
                    "choice_index": 1,
                    "choice_text": "to put the bottle back in the fridge.",
                    "score": 0.63,
                    "confidence": 0.63,
                },
            ],
        }
    ]

    pairwise_indices = planner._action_intent_pairwise_candidate_indices(  # noqa: SLF001
        state=state,
        result={"candidate_indices": [0, 3], "best_index": 0, "second_best_index": 3},
    )
    future_use_indices = planner._action_intent_future_use_candidate_indices(  # noqa: SLF001
        state=state,
        result={"candidate_indices": [0, 3], "best_index": 0, "second_best_index": 3},
    )

    assert pairwise_indices == [0, 1, 2, 3]
    assert future_use_indices == [0, 1, 2, 3]


