def test_graph_agent_action_intent_broad_generic_withhold_ignores_choice_text_categories() -> None:
    agent = object.__new__(GraphAgent)
    generic_state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <pick up towel> in video 1?",
        choices=["to clean.", "to hang the towel back up."],
        task_family="fine_grained_why_recognition",
    )
    nongeneric_state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <pick up towel> in video 1?",
        choices=["to inspect whether the towel is wet.", "to hang the towel back up."],
        task_family="fine_grained_why_recognition",
    )
    raw_result = {
        "best_index": 0,
        "reason": "This is the broadest remaining explanation, but no actual cleaning target is shown.",
        "decisive_observation": "",
    }

    assert agent._action_intent_resolution_should_withhold_broad_generic_claim_without_direct_evidence(  # noqa: SLF001
        raw_result=raw_result,
        state=generic_state,
    )
    assert agent._action_intent_resolution_should_withhold_broad_generic_claim_without_direct_evidence(  # noqa: SLF001
        raw_result=raw_result,
        state=nongeneric_state,
    )


