def test_graph_agent_action_intent_unresolved_rerank_withholds_exact_phone_record_target_close_call_without_runtime_override() -> None:
    agent = object.__new__(GraphAgent)
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <pick up phone> in video 1?",
        choices=[
            "to record the nutritional value of the coriander.",
            "to measure the ingredients.",
            "to update the app with new measurements of the broccoli.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.evidence_bundle = [
        "type=object_track; label=object_track:vid:1; time=1249.300-1253.000; object_name=phone",
        "type=frame; label=using the phone next to coriander on the kitchen scale; time=1250.100-1250.100; ongoing_action=using the phone near weighed coriander; possible_step=recording or entering ingredient information; state_change_hint=coriander remains on or beside the scale",
    ]
    state.tool_trace = [
        {
            "tool": "resolve_action_intent_future_use",
            "raw_result": {
                "best_index": 1,
                "answer": "to measure the ingredients.",
                "confidence": 0.57,
                "need_more_evidence": True,
                "candidate_indices": [0, 1, 2],
                "candidate_evidence": [
                    {
                        "index": 1,
                        "support": "The phone is used beside the scale during ingredient prep.",
                        "contradiction": "This is the broadest remaining explanation, but no actual recording target is clearly shown.",
                        "score": 0.44,
                    },
                    {
                        "index": 0,
                        "support": "The phone app is used while coriander is visibly on the scale and nearby, matching recording the coriander entry.",
                        "contradiction": "The exact nutrition screen is not fully readable, but the visible target is coriander rather than a generic measurement action.",
                        "score": 0.39,
                    },
                    {
                        "index": 2,
                        "support": "The phone could in principle be used to update a broccoli entry later.",
                        "contradiction": "No broccoli-specific target is visible here.",
                        "score": 0.18,
                    },
                ],
            },
        }
    ]

    resolved = agent._resolve_deterministic_answer_from_state(state)  # noqa: SLF001

    assert resolved is not None
    assert not any(
        "action_intent_unresolved_rerank_withheld" in item and "missing_exact_measurement_role_evidence" in item
        for item in state.working_memory
    )


