def test_toolbox_action_intent_context_scope_drops_leaky_notes() -> None:
    toolbox = AgentToolbox.__new__(AgentToolbox)
    toolbox.runtime_question = "What is the best description for why the person performed the action <pick up pot> in video 1?"
    toolbox.runtime_inputs_json = '{"video 1": {"start_time": "00:03:52.650", "end_time": "00:03:53.389"}}'

    notes = toolbox._scope_action_intent_context_notes(  # noqa: SLF001
        question=toolbox.runtime_question,
        image_paths=["/tmp/fine_grained_why_recognition_followup_003_00240.989s.jpg"],
        context_notes=[
            "type=timeline_event; label=session summary fine_grained_why_recognition; time=232.650-233.389; source=agent_timeline_summary; summary=action_intent_reason=previous answer",
            "type=audio_event; label=metal-only collision; time=232.959-233.412; event_type=audio",
            "type=object_track; label=object_track:vid:1; time=232.933-234.767; object_name=pot",
        ],
    )

    assert all("action_intent_" not in item for item in notes)
    assert all("source=agent_timeline_summary" not in item for item in notes)
    assert any("audio_event" in item for item in notes)
    assert any("object_track" in item for item in notes)


