def test_executor_pairwise_resolution_clears_future_evidence_flag() -> None:
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move glass> in video 1?",
        choices=["avoid heat", "access what's behind a glass", "make space"],
        task_family="fine_grained_why_recognition",
    )
    state.working_memory = [
        "action_intent_need_future_evidence=1 window_s=4.0 focus=disambiguate access-vs-space",
        "action_intent_second_best_index=2",
    ]
    state.open_questions = ["need_disambiguating_evidence"]
    executor = GraphAgentExecutor(toolbox=None, planner=None)  # type: ignore[arg-type]
    executor._update_reasoning_after_tool(
        state,
        "resolve_action_intent_pairwise",
        {
            "best_index": 1,
            "losing_index": 2,
            "confidence": 0.87,
            "reason": "the object behind the moved glass is retrieved before the hand leaves the area",
        },
    )
    assert "need_disambiguating_evidence" not in state.open_questions
    assert not any(
        isinstance(item, str) and item.startswith("action_intent_need_future_evidence=")
        for item in state.working_memory
    )
    assert not any(
        isinstance(item, str) and item.startswith("action_intent_second_best_index=")
        for item in state.working_memory
    )


def test_executor_future_use_resolution_records_decisive_observation_and_clears_flags() -> None:
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <pick up pot> in video 1?",
        choices=["to empty the water.", "to use the pot to weigh the butter."],
        task_family="fine_grained_why_recognition",
    )
    state.working_memory = [
        "action_intent_need_future_evidence=1 window_s=8.0 focus=future_use_evidence_needed",
        "action_intent_second_best_index=0",
    ]
    state.open_questions = ["need_disambiguating_evidence"]
    executor = GraphAgentExecutor(toolbox=None, planner=None)  # type: ignore[arg-type]
    result = {
        "best_index": 1,
        "candidate_indices": [1, 0],
        "confidence": 0.82,
        "decisive_observation": "the pot is used on the scale with butter",
        "reason": "weighing support is direct while emptying support is absent",
    }
    executor._merge_result_into_state(state, "resolve_action_intent_future_use", result)
    executor._update_reasoning_after_tool(state, "resolve_action_intent_future_use", result)

    assert "need_disambiguating_evidence" not in state.open_questions
    assert any("action_intent_future_use_observation=the pot is used on the scale with butter" in item for item in state.evidence_bundle)
    assert any("action_intent_future_use_reason=weighing support is direct" in item for item in state.evidence_bundle)
    assert not any(
        isinstance(item, str) and item.startswith("action_intent_need_future_evidence=")
        for item in state.working_memory
    )
    assert not any(
        isinstance(item, str) and item.startswith("action_intent_second_best_index=")
        for item in state.working_memory
    )


