def test_planner_action_intent_textual_fallback_scopes_evidence_to_current_window() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise AssertionError("heuristic planning should avoid model call")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move sponge> in video 1?",
        choices=[
            "so that I can lift the chop board and take the chop board to the sink.",
            "to remove coffee residue from the cup.",
            "to rinse the sponge while holding the white chop board in hand.",
            "so that the sink drainage is not covered by the sponge and the brush.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.retrieved_frames = [
        "/tmp/fine_grained_why_recognition_segment_000_00528.139s.jpg",
        "/tmp/fine_grained_why_recognition_followup_000_00530.020s.jpg",
    ]
    state.evidence_bundle = [
        "type=audio_event; label=water; time=514.846-538.692; text=water; label=water; event_type=audio",
        "type=object_track; label=object_track:vid:3; time=528.483-537.192; object_name=sponge",
        "scene_location=sink basin",
        "state_change_hint=sponge moved under running water",
        "type=timeline_event; label=session summary recipe_recipe_recognition; source=agent_timeline_summary; summary=irrelevant recipe memory",
        "type=audio_event; label=metal-only collision; time=12.417-13.780; text=metal-only collision; label=metal-only collision; event_type=audio",
        "action_intent_reason=previous model conclusion",
    ]
    evidence = planner._action_intent_scoped_textual_fallback_evidence(state, limit=16)  # noqa: SLF001
    assert "scene_location=sink basin" in evidence
    assert "state_change_hint=sponge moved under running water" in evidence
    assert any("time=514.846-538.692" in item for item in evidence)
    assert any("time=528.483-537.192" in item for item in evidence)
    assert all("recipe_recipe_recognition" not in item for item in evidence)
    assert all("source=agent_timeline_summary" not in item for item in evidence)
    assert all("time=12.417-13.780" not in item for item in evidence)
    assert all("action_intent_reason=" not in item for item in evidence)


