def test_planner_action_intent_textual_rank_is_overridden_to_recover_current_scope_after_repeated_vision_failures() -> None:
    class DummyClient:
        def complete_json(self, messages, temperature=0.0):
            raise AssertionError("heuristic planning should avoid model call")

    planner = GraphAgentPlanner(DummyClient())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move sponge> in video 1?",
        choices=[
            "so that I can lift the chop board and take the chop board to the sink.",
            "to remove coffee residue from the cup.",
            "to rinse the sponge while holding the white chop board in hand.",
            "so that the sink drainage is not covered by the sponge and the brush.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.open_questions = ["need_alternative_evidence_path"]
    state.tool_trace = [
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
    ]

    decision = PlannerDecision(
        thought="fallback rank",
        tool="rank_choices_from_state",
        args={"question": state.question, "choices": state.choices, "evidence": [], "working_memory": []},
        confidence=0.22,
    )
    stabilized = planner._recover_if_low_confidence(
        state=state,
        hints={"times": [528.139, 529.620], "input_times": [], "bbox": None},
        decision=decision,
    )

    assert stabilized.tool == "sample_sparse_frames"
    assert stabilized.args["tag"] == "fine_grained_why_recognition_segment"
    assert any(
        item.startswith("planner_override action_intent_textual_rank=rank_choices_from_state -> sample_sparse_frames")
        for item in state.working_memory
    )


