def test_planner_action_intent_textual_rank_does_not_drop_pairwise_close_call_into_generic_visual_review() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <move cheese> in video 1?",
        choices=[
            "so that I can retrieve the red curry paste.",
            "to free the center part of the chopping board for chopping the second onion.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.open_questions = ["need_alternative_evidence_path", "need_disambiguating_evidence"]
    state.retrieved_frames = [
        "/tmp/fine_grained_why_recognition_segment_000_20.000s.jpg",
        "/tmp/fine_grained_why_recognition_segment_001_20.800s.jpg",
        "/tmp/fine_grained_why_recognition_followup_000_22.000s.jpg",
        "/tmp/fine_grained_why_recognition_followup_001_23.000s.jpg",
    ]
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.45,
            "missing_evidence_types": ["need_alternative_evidence_path", "need_disambiguating_evidence"],
            "conflicts": [],
            "recommend_next_action": "need_disambiguating_evidence",
            "summary": "still insufficient",
            "evidence_gaps": [
                {
                    "gap_type": "future_outcome",
                    "priority": "high",
                    "missing_observation": "whether the red curry paste is later taken or the move only clears workspace",
                    "target_object": "cheese",
                    "target_fixture": "",
                    "time_relation": "later_after_action",
                    "source": "pairwise_close_call",
                }
            ],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["candidate:so that I can retrieve the red curry paste."],
                "blocking_comparisons": [
                    {
                        "runner_up_choice_index": 1,
                        "runner_up_choice_text": "to free the center part of the chopping board for chopping the second onion.",
                        "score_gap": 0.02,
                        "unresolved_evidence": "need later evidence showing whether the revealed ingredient is actually taken or the board is only cleared",
                    }
                ],
                "recommended_next_step": "need_disambiguating_evidence",
                "finish_mode": "needs_more_evidence",
                "summary": "still insufficient",
            },
            "action_intent_hypotheses": [
                {
                    "choice_index": 0,
                    "choice_text": "so that I can retrieve the red curry paste.",
                    "score": 0.64,
                    "confidence": 0.64,
                },
                {
                    "choice_index": 1,
                    "choice_text": "to free the center part of the chopping board for chopping the second onion.",
                    "score": 0.62,
                    "confidence": 0.62,
                },
            ],
        }
    ]
    state.tool_trace = [
        {
            "tool": "resolve_action_intent_pairwise",
            "raw_result": {
                "best_index": 0,
                "losing_index": 1,
                "confidence": 0.68,
                "need_more_evidence": True,
                "needed_observation": "whether the red curry paste is later taken or the move only clears workspace",
            },
        },
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "infer_action_intent", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
        {"tool": "rank_choices_from_state", "raw_result": {"best_index": 0, "confidence": 0.76}},
    ]

    decision = planner._recover_if_low_confidence(  # noqa: SLF001
        state=state,
        hints={"times": [20.0, 21.0], "input_times": [], "bbox": None},
        decision=PlannerDecision(
            thought="textual fallback rank",
            tool="rank_choices_from_state",
            args={"question": state.question, "choices": [str(choice) for choice in state.choices]},
            confidence=0.76,
        ),
    )

    assert decision.tool == "query_object"
    assert not any(
        item.startswith(
            "planner_guard=textual_rank_prefers_existing_pairwise_resolution_over_generic_visual_review"
        )
        for item in state.working_memory
    )


