def test_planner_action_intent_heuristic_state_candidate_selection_is_not_driven_by_specialized_tool_name() -> None:
    def run_case(tool_name: str) -> tuple[PlannerDecision, list[str]]:
        planner = GraphAgentPlanner(model_client=SimpleNamespace())
        state = AgentState(
            video_id="vid",
            question="What is the best description for why the person performed the action <move bottle> in video 1?",
            choices=[
                "to check the label.",
                "to put the bottle back in the fridge.",
                "to make space on the shelf.",
            ],
            task_family="fine_grained_why_recognition",
        )
        state.tool_trace = [
            {
                "tool": tool_name,
                "raw_result": {
                    "best_index": 1,
                    "answer": "to put the bottle back in the fridge.",
                    "confidence": 0.84,
                    "need_more_evidence": False,
                    "reason": "the bottle is moved away, but the later downstream target is still not explicit enough",
                },
            }
        ]
        state.verification_history = [
            {
                "sufficient": False,
                "confidence": 0.39,
                "missing_evidence_types": [],
                "conflicts": [],
                "recommend_next_action": "",
                "summary": "still insufficient",
                "evidence_gaps": [],
                "sufficiency_decision": {
                    "sufficient": False,
                    "missing_gap_types": ["future_outcome"],
                    "blocking_hypotheses": [],
                    "blocking_comparisons": [],
                    "recommended_next_step": "",
                    "finish_mode": "needs_more_evidence",
                    "summary": "still insufficient",
                },
            }
        ]
        planner._recover_from_open_questions = lambda **kwargs: PlannerDecision(  # type: ignore[method-assign]
            thought="no actionable open-question recovery",
            tool="rank_choices_from_state",
            args={"question": state.question, "choices": state.choices},
        )
        planner._best_state_candidate_plan = lambda **kwargs: CandidatePlan(  # type: ignore[method-assign]
            decision=PlannerDecision(
                thought="targeted fridge follow-up",
                tool="query_spatial_context",
                args={"object_name": "fridge", "time_s": 53.0, "limit": 8},
            ),
            cost=1,
            gain=5,
            risk=1,
            rationale="structured insufficiency still favors a targeted downstream fridge check",
        )
        planner._build_action_intent_resolution_transition_recovery_decision = lambda **kwargs: None  # type: ignore[method-assign]
        planner._build_action_intent_peak_guided_followup_decision = lambda **kwargs: None  # type: ignore[method-assign]
        planner._action_intent_resolution_needs_more_evidence = lambda **kwargs: False  # type: ignore[method-assign]
        planner._action_intent_result_is_weak_generic_claim = lambda **kwargs: False  # type: ignore[method-assign]
        planner._action_intent_result_is_workspace_or_final_placement_close_call = lambda **kwargs: False  # type: ignore[method-assign]
        planner._action_intent_resolution_payload_is_ready_to_finish = lambda **kwargs: True  # type: ignore[method-assign]
        planner._action_intent_primary_gap = lambda _state: None  # type: ignore[method-assign]

        decision = planner._heuristic_fallback(  # noqa: SLF001
            state=state,
            hints={"times": [50.0, 51.0], "input_times": [], "bbox": None},
        )
        return decision, list(state.working_memory)

    pairwise_decision, pairwise_memory = run_case("resolve_action_intent_pairwise")
    future_decision, future_memory = run_case("resolve_action_intent_future_use")

    assert pairwise_decision.tool == "query_spatial_context"
    assert future_decision.tool == "query_spatial_context"
    assert pairwise_decision.args == future_decision.args
    assert any(
        item.startswith("planner_guard=heuristic_fallback_prefers_state_candidate=query_spatial_context")
        for item in pairwise_memory
    )
    assert any(
        item.startswith("planner_guard=heuristic_fallback_prefers_state_candidate=query_spatial_context")
        for item in future_memory
    )


