def test_planner_action_intent_gap_late_followup_candidate_expands_with_window_level() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    base_state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
            "to pour water into the pan.",
        ],
        task_family="fine_grained_why_recognition",
    )
    base_state.open_questions = []
    base_state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.42,
            "missing_evidence_types": [],
            "conflicts": [],
            "recommend_next_action": "",
            "summary": "still insufficient",
            "evidence_gaps": [
                {
                    "gap_type": "future_outcome",
                    "priority": "high",
                    "missing_observation": "需要确认 bottle 后来是否被放回 fridge，还是继续被使用",
                    "target_object": "bottle",
                    "target_fixture": "fridge",
                    "time_relation": "later_after_action",
                    "source": "future_use_close_call",
                }
            ],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["future_outcome"],
                "recommended_next_step": "",
                "finish_mode": "needs_more_evidence",
                "summary": "still insufficient",
            },
        }
    ]
    hints = {"times": [50.0, 51.0], "input_times": [], "bbox": None}

    level0 = AgentState(**base_state.__dict__ | {"search_budget": {"window_level": 0}})
    level1 = AgentState(**base_state.__dict__ | {"search_budget": {"window_level": 1}})
    level2 = AgentState(**base_state.__dict__ | {"search_budget": {"window_level": 2}})

    ranked0 = planner._rank_state_candidate_plans(state=level0, hints=hints, used_tools=[])  # noqa: SLF001
    ranked1 = planner._rank_state_candidate_plans(state=level1, hints=hints, used_tools=[])  # noqa: SLF001
    ranked2 = planner._rank_state_candidate_plans(state=level2, hints=hints, used_tools=[])  # noqa: SLF001

    late0 = next(item for item in ranked0 if item.decision.args.get("tag") == "fine_grained_why_recognition_gap_late_followup")
    late1 = next(item for item in ranked1 if item.decision.args.get("tag") == "fine_grained_why_recognition_gap_late_followup")
    late2 = next(item for item in ranked2 if item.decision.args.get("tag") == "fine_grained_why_recognition_gap_late_followup")

    assert late0.decision.args["end_time"] == 59.0
    assert late1.decision.args["end_time"] == 61.0
    assert late2.decision.args["end_time"] == 63.0
    assert late0.decision.args["sample_count"] == 5
    assert late1.decision.args["sample_count"] == 6
    assert late2.decision.args["sample_count"] == 7


def test_planner_next_action_decorates_finish_with_metadata_from_sufficiency_and_budget() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="q",
        choices=["a", "b"],
        task_family="fine_grained_why_recognition",
        max_steps=4,
    )
    state.final_prediction = 1
    state.final_answer = "b"
    state.confidence = 0.37
    state.initialize_search_budget()
    state.search_budget["tool_steps_used"] = 4
    state.search_budget["budget_exhausted"] = True
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.37,
            "missing_evidence_types": ["need_disambiguating_evidence"],
            "conflicts": [],
            "recommend_next_action": "need_disambiguating_evidence",
            "summary": "budget exhausted test",
            "evidence_gaps": [
                {
                    "gap_type": "future_outcome",
                    "priority": "high",
                    "missing_observation": "still need later evidence",
                    "target_object": "bottle",
                    "target_fixture": "fridge",
                    "time_relation": "later_after_action",
                    "source": "future_use_close_call",
                }
            ],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["future_outcome"],
                "recommended_next_step": "need_disambiguating_evidence",
                "finish_mode": "finish_budget_exhausted_best_guess",
                "summary": "budget exhausted test",
            },
        }
    ]

    decision = planner.next_action(state=state, tool_schemas=[], hints={})

    assert decision.tool == "finish"
    assert decision.args["final_metadata"]["finish_reason"] == "finish_budget_exhausted_best_guess"
    assert decision.args["final_metadata"]["remaining_gaps"][0]["gap_type"] == "future_outcome"
    assert decision.args["final_metadata"]["final_support_summary"] == "budget exhausted test"
    assert decision.args["final_metadata"]["used_budget"]["budget_exhausted"] is True


