def test_planner_finish_metadata_excludes_structured_blockers_and_hypothesis_summaries() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="q",
        choices=["a", "b"],
        task_family="fine_grained_why_recognition",
    )
    state.open_questions = []
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.42,
            "missing_evidence_types": [],
            "conflicts": [],
            "recommend_next_action": "",
            "summary": "runner-up still blocks finish",
            "evidence_gaps": [],
            "sufficiency_decision": {
                "blocking_hypotheses": ["candidate:b"],
                "blocking_comparisons": [
                    {
                        "leading_choice_index": 0,
                        "leading_choice_text": "a",
                        "runner_up_choice_index": 1,
                        "runner_up_choice_text": "b",
                        "score_gap": 0.03,
                        "unresolved_evidence": "need later evidence",
                    }
                ],
            },
            "action_intent_hypotheses": [
                {
                    "choice_index": 0,
                    "choice_text": "a",
                    "score": 0.66,
                    "confidence": 0.66,
                    "comparison_summary": "top hypothesis currently leads runner-up with score_gap=0.03",
                    "missing_observations": ["whether the object is used immediately after being moved"],
                    "contradiction_evidence": [],
                },
                {
                    "choice_index": 1,
                    "choice_text": "b",
                    "score": 0.63,
                    "confidence": 0.63,
                    "comparison_summary": "runner-up still plausible until later evidence arrives",
                    "missing_observations": ["whether the object is returned to its original location"],
                    "contradiction_evidence": ["the current evidence does not yet show the final placement"],
                },
            ],
        }
    ]

    decorated = planner._decorate_finish_decision_with_metadata(  # noqa: SLF001
        state=state,
        decision=PlannerDecision(
            thought="fallback finish",
            tool="finish",
            args={"prediction": 0, "answer": "a", "confidence": 0.42},
            done=True,
            answer="a",
            prediction=0,
            confidence=0.42,
        ),
    )

    assert "blocking_hypotheses" not in decorated.args["final_metadata"]
    assert "blocking_comparisons" not in decorated.args["final_metadata"]
    assert "top_hypothesis" not in decorated.args["final_metadata"]
    assert "runner_up" not in decorated.args["final_metadata"]


