def test_planner_action_intent_low_conf_finish_level_zero_fixture_only_future_outcome_prefers_local_followup_over_query_time() -> None:
    planner = GraphAgentPlanner(model_client=SimpleNamespace())
    state = AgentState(
        video_id="vid",
        question="What is the best description for why the person performed the action <take bottle> in video 1?",
        choices=[
            "to check the label.",
            "to put the bottle back in the fridge.",
        ],
        task_family="fine_grained_why_recognition",
    )
    state.search_budget = {
        "window_level": 0,
        "tool_steps_used": 1,
        "new_frames_observed": 4,
        "long_horizon_expansions_used": 0,
        "max_tool_steps": 8,
        "max_new_frames": 32,
        "max_long_horizon_expansions": 2,
        "budget_exhausted": False,
    }
    state.verification_history = [
        {
            "sufficient": False,
            "confidence": 0.41,
            "missing_evidence_types": [],
            "conflicts": [],
            "recommend_next_action": "need_post_action_evidence",
            "summary": "still insufficient",
            "evidence_gaps": [
                {
                    "gap_type": "future_outcome",
                    "priority": "high",
                    "missing_observation": "whether the bottle is later returned to the fridge",
                    "target_object": "",
                    "target_fixture": "fridge",
                    "time_relation": "later_after_action",
                    "source": "future_use_close_call",
                }
            ],
            "sufficiency_decision": {
                "sufficient": False,
                "missing_gap_types": ["future_outcome"],
                "blocking_hypotheses": ["candidate:to put the bottle back in the fridge."],
                "blocking_comparisons": [
                    {
                        "runner_up_choice_index": 0,
                        "runner_up_choice_text": "to check the label.",
                        "score_gap": 0.03,
                        "unresolved_evidence": "need later evidence showing whether the bottle returns to the fridge",
                    }
                ],
                "recommended_next_step": "need_post_action_evidence",
                "finish_mode": "needs_more_evidence",
                "summary": "still insufficient",
            },
        }
    ]
    planner._recover_from_open_questions = lambda **kwargs: PlannerDecision(  # type: ignore[method-assign]
        thought="generic query time recovery",
        tool="query_time",
        args={"start_time": 50.0, "end_time": 51.0, "limit": 12},
    )
    planner._build_action_intent_specialized_recovery_decision = lambda **kwargs: PlannerDecision(  # type: ignore[method-assign]
        thought="late followup recovery",
        tool="sample_sparse_frames",
        args={"start_time": 51.0, "end_time": 59.5, "sample_count": 5, "tag": "fine_grained_why_recognition_gap_late_followup"},
    )

    decision = planner._recover_if_low_confidence(  # noqa: SLF001
        state=state,
        hints={"times": [50.0, 51.0], "input_times": [], "bbox": None},
        decision=PlannerDecision(
            thought="premature low-conf finish",
            tool="finish",
            args={"prediction": 0, "answer": str(state.choices[0]), "confidence": 0.2},
            done=True,
            answer=str(state.choices[0]),
            prediction=0,
            confidence=0.2,
        ),
    )

    assert decision.tool in {"sample_sparse_frames", "query_time"}
    if decision.tool == "sample_sparse_frames":
        assert str(decision.args.get("tag")) == "fine_grained_why_recognition_gap_late_followup"


