def test_agent_state_trim_memory_limits_buffers() -> None:
    state = AgentState(
        video_id="vid",
        question="q",
        choices=["a"],
        task_family="task",
    )
    state.working_memory = [f"m{i}" for i in range(200)]
    state.evidence_bundle = [f"e{i}" for i in range(200)]
    state.retrieved_frames = [f"/tmp/{i}.jpg" for i in range(120)]
    state.retrieved_nodes = [{"node_id": f"n{i}"} for i in range(120)]
    state.retrieved_node_ids = [f"n{i}" for i in range(120)]
    state.tool_trace = [{"tool": f"t{i}"} for i in range(150)]
    state.tool_failures = [{"tool": f"f{i}"} for i in range(100)]
    state.ineffective_tools = [{"tool": f"i{i}"} for i in range(100)]
    state.trim_memory()
    assert len(state.working_memory) == 120
    assert len(state.evidence_bundle) == 120
    assert len(state.retrieved_frames) == 80
    assert len(state.retrieved_nodes) == 80
    assert len(state.tool_trace) == 120


