def test_graph_agent_video_session_skips_compressed_writeback_when_conflicts_exist(monkeypatch, tmp_path: Path) -> None:
    monkeypatch.setenv("FOOD_AGENT_GRAPH_MEMORY_ROOT", (tmp_path / "graph_memory").as_posix())
