def test_video_session_summary_helpers() -> None:
    payload = {
        "tool_trace": [
            {"tool": "query_state"},
            {"tool": "run_ocr_on_image", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
            {"tool": "query_ocr"},
            {"tool": "rank_choices_from_state"},
        ],
        "working_memory": [
            "reuse:type=timeline_event; label=stirring",
            "reuse_relation:type=ocr_reading; label=scale",
            "planner_override verifier_blocked_finish=finish -> query_ocr",
            "ocr_reading=98 g",
        ],
        "tool_failures": [{"tool": "run_ocr_on_image"}],
        "ineffective_tools": [],
    }
    assert extract_tool_calls(payload) == ["query_state", "run_ocr_on_image", "query_ocr", "rank_choices_from_state"]
    assert count_reuse_memory(payload) == 1
    assert count_relation_reuse(payload) == 1
    assert count_planner_overrides(payload) == 1
    assert count_verifier_blocked_finish(payload) == 1
    assert count_session_failed_tool_recoveries(payload) == 1
    assert count_session_ineffective_tool_avoidances(payload) == 0
    summary = build_session_summary(
        "vid1",
        [
            {
                "vqa_id": "a",
                "task_family": "task_a",
                "correct": True,
                "tool_trace": [{"tool": "query_state"}],
                "working_memory": ["reuse:type=timeline_event", "reuse_relation:type=timeline_event"],
                "tool_failures": [],
                "ineffective_tools": [],
            },
            {
                "vqa_id": "b",
                "task_family": "task_b",
                "correct": False,
                "tool_trace": [
                    {"tool": "run_ocr_on_image", "raw_result": {"tool_failed": True, "error_type": "RuntimeError"}},
                    {"tool": "query_ocr"},
                    {"tool": "sample_sparse_frames", "raw_result": {"tool_ineffective": True, "reason": "no_new_evidence"}},
                    {"tool": "expand_graph_context"},
                ],
                "working_memory": [
                    "reuse:type=ocr_reading",
                    "reuse_relation:type=ocr_reading",
                    "planner_override blocked_tool=run_ocr_on_image -> query_ocr",
                    "ocr_reading=98 g",
                ],
                "tool_failures": [{"tool": "run_ocr_on_image"}],
                "ineffective_tools": [{"tool": "sample_sparse_frames"}],
            },
        ],
        Path("/tmp/session_trace.jsonl"),
    )
    assert summary["video_id"] == "vid1"
    assert summary["count"] == 2
    assert summary["correct"] == 1
    assert summary["avg_reuse_memory_items"] == 1.0
    assert summary["avg_relation_reuse_items"] == 1.0
    assert summary["avg_planner_override_count"] == 0.5
    assert summary["avg_tool_failure_count"] == 0.5
    assert summary["avg_ineffective_tool_count"] == 0.5
    assert summary["avg_failed_tool_recovery_count"] == 0.5
    assert summary["avg_ineffective_tool_avoidance_count"] == 0.5
    assert summary["tool_counts"]["query_state"] == 1
    assert summary["tool_counts"]["query_ocr"] == 1
    assert build_video_session_run_name("vid1", "task_a", 5) == "vid1_task_a_limit5"


