def test_stratified_probe_skip_completed_sample_respects_retry_budget() -> None:
    completed = {
        "sample:1": VQAPrediction(
            sample_id="sample:1",
            baseline="graph-agent-stratified-probe",
            task_family="task_a",
            video_id="vid1",
            question="q",
            choices=["0"],
            gold=0,
            prediction=0,
            correct=False,
            evidence_ids=[],
            tool_calls=[],
            failure_type="agent_error:RuntimeError",
            attempt_count=2,
        )
    }
    retry_state = {"sample:1": {"attempt_count": 2}}
    assert run_graph_agent_stratified_probe.should_skip_completed_sample(
        sample_id="sample:1",
        completed=completed,
        retry_state=retry_state,
        max_retries_per_sample=2,
    )
    assert not run_graph_agent_stratified_probe.should_skip_completed_sample(
        sample_id="sample:1",
        completed=completed,
        retry_state={"sample:1": {"attempt_count": 1}},
        max_retries_per_sample=3,
    )


