def test_run_graph_agent_open_query_script_writes_result(monkeypatch, tmp_path: Path) -> None:
    class DummyAgent:
        def __init__(self, paths=None):
            self.paths = paths
            self.rebuilt = []
            self.reset = []

        def rebuild_video_graph(self, video_id):
            self.rebuilt.append(video_id)

        def reset_video_session(self, video_id):
            self.reset.append(video_id)

        def answer_open_query(self, *, video_id, question, inputs_json="{}", task_family="open_query", max_steps=8, query_id=""):
            assert video_id == "vid1"
            assert question == "What happened?"
            assert task_family == "open_query"
            return GraphAgentResult(
                vqa_id="open_query:vid1:test",
                video_id=video_id,
                task_family=task_family,
                prediction=None,
                answer_text="The cook stirred the bowl.",
                evidence_bundle=["type=timeline_event; label=stirring bowl"],
                tool_trace=[{"tool": "query_time"}],
                raw_model_output="The cook stirred the bowl.",
                working_memory=["reuse:type=timeline_event"],
                retrieved_frames=[],
                visited_times=[],
                artifacts=[],
                confidence=0.7,
                elapsed_seconds=0.12,
            )

    monkeypatch.setattr(run_graph_agent_open_query, "GraphAgent", DummyAgent)
    monkeypatch.setattr(run_graph_agent_open_query, "load_env_file", lambda path: None)
    monkeypatch.setattr(
        run_graph_agent_open_query,
        "parse_args",
        lambda: argparse.Namespace(
            env_file=tmp_path / "model.env",
            video_id="vid1",
            question="What happened?",
            inputs_json="{}",
            task_family="open_query",
                query_id="",
                max_steps=4,
                out_file=tmp_path / "open_query_result.json",
                reset_session=False,
                rebuild_graph=False,
            ),
        )
    assert run_graph_agent_open_query.main() == 0
    payload = json.loads((tmp_path / "open_query_result.json").read_text(encoding="utf-8"))
    assert payload["video_id"] == "vid1"
    assert payload["prediction"] is None
    assert payload["answer_text"] == "The cook stirred the bowl."


