def test_build_graph_agent_small_run_report_aggregates_probe_and_real_artifacts(tmp_path: Path) -> None:
    probe_summary_path = tmp_path / "probe_summary.json"
    probe_summary_path.write_text(
        json.dumps(
            {
                "progress": {
                    "avg_tool_call_count": 2.0,
                    "avg_reasoning_step_count": 2.5,
                    "avg_elapsed_seconds": 3.0,
                    "avg_total_tokens": 40.0,
                    "avg_estimated_cost": 0.5,
                },
                "failure_summary": {"overall": {"reasoning_error": 1}},
                "attempt_summary": {"max_attempt_count": 2, "avg_attempt_count": 1.5, "retried_sample_count": 1},
                "video_session_summary": {"video_count": 1, "videos": [{"video_id": "vid1", "count": 2}]},
            },
            ensure_ascii=False,
        ),
        encoding="utf-8",
    )
    real_summary_path = tmp_path / "real_summary.json"
    real_summary_path.write_text(
        json.dumps(
            {
                "count": 2,
                "accuracy": 0.5,
                "memory_reuse_rate": 0.5,
                "relation_reuse_rate": 0.5,
                "raw_revisit_rate": 0.5,
                "planner_override_count": 1,
                "verifier_blocked_finish_count": 1,
                "tool_failure_recovery_rate": 1.0,
                "ineffective_tool_avoidance_rate": 1.0,
                "cached_artifact_reuse_hits": 1,
                "cached_artifact_reuse_gain": {"cached_artifact_hit_count": 1},
                "same_video_follow_up_cost_reduction": {"follow_up_minus_first_estimated_cost": -0.2},
                "video_session_summary": {"video_count": 1, "videos": [{"video_id": "vid1", "count": 2}]},
                "failure_counts": {"none": 1, "reasoning_error": 1},
                "attempt_summary": {"max_attempt_count": 1, "avg_attempt_count": 1.0, "retried_sample_count": 0},
            },
            ensure_ascii=False,
        ),
        encoding="utf-8",
    )
    prediction_path = tmp_path / "predictions.jsonl"
    prediction_path.write_text(
        "\n".join(
            [
                json.dumps(
                    {
                        "sample_id": "sample:1",
                        "task_family": "ingredient_ingredient_weight",
                        "video_id": "vid1",
                        "prediction": 0,
                        "gold": 0,
                        "correct": True,
                        "tool_calls": ["query_ingredient_measurement", "retrieve_cached_artifacts"],
                        "tool_trace": [{"tool": "query_ingredient_measurement"}, {"tool": "retrieve_cached_artifacts"}],
                        "working_memory": ["reuse:graph_seed", "reuse_relation:ingredient_weight"],
                        "usage": {"prompt_tokens": 10, "completion_tokens": 5, "total_tokens": 15, "estimated_cost": 0.2},
                        "elapsed_seconds": 2.0,
                        "failure_type": None,
                        "attempt_count": 1,
                    },
                    ensure_ascii=False,
                ),
                json.dumps(
                    {
                        "sample_id": "sample:2",
                        "task_family": "ingredient_ingredient_retrieval",
                        "video_id": "vid1",
                        "prediction": 1,
                        "gold": 2,
                        "correct": False,
                        "tool_calls": ["sample_sparse_frames", "query_time"],
                        "tool_trace": [{"tool": "sample_sparse_frames"}, {"tool": "query_time"}],
                        "working_memory": ["planner_override retry_after_failure"],
                        "tool_failures": ["sample_sparse_frames"],
                        "ineffective_tools": ["sample_sparse_frames"],
                        "usage": {"prompt_tokens": 20, "completion_tokens": 10, "total_tokens": 30, "estimated_cost": 0.4},
                        "elapsed_seconds": 3.0,
                        "failure_type": "reasoning_error",
                        "attempt_count": 2,
                    },
                    ensure_ascii=False,
                ),
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    report = build_graph_agent_small_run_report.build_small_run_report(
        probe_summaries=[probe_summary_path],
        real_summaries=[real_summary_path],
        probe_predictions=[prediction_path],
        real_predictions=[],
    )
    assert report["coverage"]["task_family_count"] == 2
    assert report["accuracy_summary"]["accuracy"] == 0.5
    assert report["agent_metrics"]["memory_reuse_rate"] == 0.5
    assert report["agent_metrics"]["cached_artifact_reuse_hits"] == 1
    assert report["attempt_summary"]["max_attempt_count"] == 2
    assert report["failure_summary"]["overall"]["reasoning_error"] == 1


def test_run_graph_agent_small_real_why_eval_builds_summary_and_error_analysis() -> None:
    rows = [
        {"vqa_id": "why:1", "cluster": "future-use-cluster"},
        {"vqa_id": "why:2", "cluster": "state-change-cluster"},
    ]
    predictions = [
        {
            "vqa_id": "why:1",
            "cluster": "future-use-cluster",
            "prediction": 1,
            "gold": 1,
            "correct": True,
            "failure_type": None,
            "elapsed_seconds": 12.5,
            "tool_calls": ["infer_action_intent", "query_object"],
            "usage": {"prompt_tokens": 100, "completion_tokens": 10, "total_tokens": 110, "estimated_cost": 0.0},
            "final_metadata": {"finish_reason": "needs_more_evidence"},
            "latest_verification": {
                "missing_evidence_types": ["need_post_action_evidence"],
                "evidence_gaps": [{"gap_type": "future_outcome"}],
                "sufficiency_decision": {
                    "finish_mode": "needs_more_evidence",
                    "recommended_next_step": "need_post_action_evidence",
                },
            },
            "action_intent_trace": [
                {
                    "primary_gap": {"gap_type": "future_outcome"},
                    "primary_gap_recovery_trace": "primary_gap_recovery_trace=future_outcome->query_object",
                    "recommended_next_action": "query_object",
                    "finish_mode": "needs_more_evidence",
                },
                {
                    "primary_gap": {"gap_type": "immediate_outcome"},
                    "primary_gap_recovery_trace": "primary_gap_recovery_trace=immediate_outcome->sample_local_frames",
                    "recommended_next_action": "sample_local_frames",
                    "finish_mode": "needs_more_evidence",
                },
            ],
        },
        {
            "vqa_id": "why:2",
            "cluster": "state-change-cluster",
            "prediction": None,
            "gold": 0,
            "correct": False,
            "failure_type": "runner_error:SampleTimeoutError",
            "elapsed_seconds": None,
            "tool_calls": [],
            "usage": {},
            "final_metadata": {"finish_reason": "finish_budget_exhausted_best_guess"},
            "latest_verification": {
                "missing_evidence_types": [],
                "evidence_gaps": [{"gap_type": "immediate_outcome"}],
                "sufficiency_decision": {
                    "finish_mode": "finish_insufficient_evidence",
                    "recommended_next_step": "",
                },
            },
        },
    ]
    summary = run_graph_agent_small_real_why_eval.build_summary(rows=rows, predictions=predictions)
    analysis = run_graph_agent_small_real_why_eval.build_error_analysis(rows=rows, predictions=predictions, summary=summary)
    assert summary["selection_count"] == 2
    assert summary["completed_count"] == 2
    assert summary["correct_count"] == 1
    assert summary["gap_type_counts"]["future_outcome"] == 1
    assert summary["gap_type_counts"]["immediate_outcome"] == 1
    assert summary["finish_mode_counts"]["needs_more_evidence"] == 1
    assert summary["finish_mode_counts"]["finish_budget_exhausted_best_guess"] == 1
    assert summary["budget_exhausted_count"] == 1
    assert summary["action_intent_trace_count"] == 1
    assert summary["avg_trace_steps"] == 2.0
    assert summary["primary_gap_change_count"] == 1
    assert summary["recommended_next_action_change_count"] == 1
    assert "gap_type_counts" in analysis
    assert "runner_error:SampleTimeoutError" in analysis
    assert "observation_trace" in analysis
    assert "final_finish_reason" in analysis
    assert "gap future_outcome->immediate_outcome" in analysis
    assert "next_action query_object->sample_local_frames" in analysis


def test_run_graph_agent_small_real_why_eval_gap_counts_can_fall_back_to_trace_primary_gap_type() -> None:
    rows = [{"vqa_id": "why:trace-gap", "cluster": "future-use-cluster"}]
    predictions = [
        {
            "vqa_id": "why:trace-gap",
            "cluster": "future-use-cluster",
            "prediction": 1,
            "gold": 1,
            "correct": True,
            "failure_type": None,
            "elapsed_seconds": 2.0,
            "tool_calls": ["query_object"],
            "usage": {"prompt_tokens": 10, "completion_tokens": 2, "total_tokens": 12, "estimated_cost": 0.0},
            "final_metadata": {"finish_reason": "needs_more_evidence"},
            "latest_verification": {
                "missing_evidence_types": [],
                "evidence_gaps": [],
                "sufficiency_decision": {
                    "finish_mode": "needs_more_evidence",
                    "recommended_next_step": "need_disambiguating_evidence",
                },
            },
            "action_intent_trace": [
                {
                    "summary": "still insufficient",
                    "primary_gap": {"gap_type": "future_outcome"},
                    "primary_gap_recovery_trace": "primary_gap_recovery_trace=future_outcome->query_object",
                    "recommended_next_action": "query_object",
                    "finish_mode": "needs_more_evidence",
                }
            ],
        }
    ]

    summary = run_graph_agent_small_real_why_eval.build_summary(rows=rows, predictions=predictions)

    assert summary["gap_type_counts"]["future_outcome"] == 1
    assert summary["trace_primary_gap_type_counts"]["future_outcome"] == 1


